const n={mongodb:{name:"MongoDB",icon:"M",color:"from-green-400 to-green-600",chapters:[{id:"intro",title:"MongoDB 简介",content:[{type:"heading",text:"什么是 MongoDB"},{type:"paragraph",text:"MongoDB 是一个基于分布式文件存储的数据库，由 C++ 语言编写。旨在为 WEB 应用提供可扩展的高性能数据存储解决方案。"},{type:"heading",text:"核心特点"},{type:"list",items:["<strong>文档型存储</strong>：数据以 BSON（Binary JSON）格式存储，灵活的文档模型","<strong>高性能</strong>：支持内存缓存，查询性能高","<strong>高可用性</strong>：支持自动故障转移和副本集","<strong>可扩展性</strong>：支持水平分片，轻松扩展","<strong>丰富的查询语言</strong>：支持丰富的查询表达式和聚合框架","<strong>无模式</strong>：集合不需要预定义结构，便于快速迭代"]},{type:"heading",text:"应用场景"},{type:"list",items:["内容管理系统（CMS）","实时大数据分析","移动应用后端","物联网（IoT）数据存储","社交网络应用","游戏数据存储"]}]},{id:"vs-mysql",title:"MongoDB vs MySQL",content:[{type:"heading",text:"核心区别对比"},{type:"table",headers:["对比项","MongoDB","MySQL"],rows:[["数据模型","文档型（无模式）","关系型（表结构）"],["存储格式","BSON（类JSON）","表格（行/列）"],["Schema灵活性","灵活，可随时修改字段","固定，需预先定义表结构"],["扩展方式","水平分片","垂直扩展为主"],["事务支持","4.0+支持多文档事务","完整ACID事务"],["查询语言","丰富的查询API","标准SQL"],["性能特点","高写入性能，适合大数据","复杂查询优化成熟"],["适用场景","半结构化/非结构化数据","结构化数据，复杂事务"]]},{type:"heading",text:"什么时候选择 MongoDB"},{type:"list",items:["数据结构经常变化，需要灵活的 Schema","需要存储大量的日志、事件流等半结构化数据","需要水平扩展能力","开发迭代速度快，Schema 不确定","需要高吞吐量的写入操作"]},{type:"heading",text:"什么时候选择 MySQL"},{type:"list",items:["数据结构稳定，关系复杂","需要强事务保证（如金融系统）","需要复杂的多表关联查询","团队更熟悉 SQL 生态","需要成熟的分析和报表工具"]}]},{id:"key-concepts",title:"核心概念",content:[{type:"heading",text:"基本概念对比"},{type:"paragraph",text:"理解 MongoDB 与关系型数据库的术语对应关系"},{type:"table",headers:["MongoDB","MySQL","说明"],rows:[["Database（数据库）","Database","数据库容器"],["Collection（集合）","Table","文档集合"],["Document（文档）","Row（行）","数据记录"],["Field（字段）","Column（列）","数据字段"],["Index（索引）","Index","提高查询效率"],["_id（主键）","Primary Key","唯一标识符"]]},{type:"heading",text:"BSON 数据类型"},{type:"list",items:["<strong>String</strong>：字符串","<strong>Integer</strong>：整数（32位/64位）","<strong>Double</strong>：浮点数","<strong>Boolean</strong>：布尔值","<strong>Array</strong>：数组","<strong>Object</strong>：嵌入式对象","<strong>Null</strong>：空值","<strong>Date</strong>：日期时间","<strong>ObjectId</strong>：对象ID（文档唯一标识）","<strong>Binary Data</strong>：二进制数据"]}]},{id:"crud-operations",title:"CRUD 操作",content:[{type:"heading",text:"创建文档 (Create)"},{type:"code",lang:"javascript",code:'// 插入单条文档\ndb.users.insertOne({\n  name: "张三",\n  age: 25,\n  email: "zhangsan@example.com",\n  tags: ["developer", "mongodb"],\n  createdAt: new Date()\n})\n\n// 插入多条文档\ndb.users.insertMany([\n  { name: "李四", age: 30, role: "admin" },\n  { name: "王五", age: 28, role: "user" }\n])'},{type:"heading",text:"读取文档 (Read)"},{type:"code",lang:"javascript",code:'// 查询所有文档\ndb.users.find()\n\n// 条件查询\ndb.users.find({ age: { $gte: 25 } })\n\n// 查询单个文档\ndb.users.findOne({ email: "zhangsan@example.com" })\n\n// 投影（只返回指定字段）\ndb.users.find({}, { name: 1, email: 1, _id: 0 })\n\n// 排序\ndb.users.find().sort({ age: -1 })\n\n// 分页\ndb.users.find().skip(10).limit(5)'},{type:"heading",text:"更新文档 (Update)"},{type:"code",lang:"javascript",code:'// 更新单个文档\ndb.users.updateOne(\n  { email: "zhangsan@example.com" },\n  { $set: { age: 26, updatedAt: new Date() } }\n)\n\n// 更新多个文档\ndb.users.updateMany(\n  { role: "user" },\n  { $set: { status: "active" } }\n)\n\n// 替换整个文档\ndb.users.replaceOne(\n  { email: "zhangsan@example.com" },\n  {\n    name: "张三",\n    age: 26,\n    email: "zhangsan@example.com",\n    role: "senior-developer"\n  }\n)'},{type:"heading",text:"删除文档 (Delete)"},{type:"code",lang:"javascript",code:'// 删除单个文档\ndb.users.deleteOne({ email: "zhangsan@example.com" })\n\n// 删除多个文档\ndb.users.deleteMany({ status: "inactive" })\n\n// 删除所有文档\ndb.users.deleteMany({})'}]},{id:"indexing",title:"索引",content:[{type:"heading",text:"索引概述"},{type:"paragraph",text:"索引可以显著提高查询性能，但会增加写入开销和存储空间。"},{type:"heading",text:"创建索引"},{type:"code",lang:"javascript",code:'// 创建单字段索引\ndb.users.createIndex({ email: 1 })\n\n// 创建复合索引\ndb.users.createIndex({ name: 1, age: -1 })\n\n// 创建唯一索引\ndb.users.createIndex({ email: 1 }, { unique: true })\n\n// 创建稀疏索引（只索引存在该字段的文档）\ndb.users.createIndex({ phone: 1 }, { sparse: true })\n\n// 创建文本索引（全文搜索）\ndb.articles.createIndex({ content: "text" })\n\n// 查看索引\ndb.users.getIndexes()\n\n// 删除索引\ndb.users.dropIndex("email_1")'},{type:"heading",text:"索引类型"},{type:"list",items:["<strong>单字段索引</strong>：对单个字段建立索引","<strong>复合索引</strong>：对多个字段组合建立索引","<strong>唯一索引</strong>：确保字段值唯一","<strong>稀疏索引</strong>：只索引包含该字段的文档","<strong>文本索引</strong>：支持文本搜索","<strong>地理空间索引</strong>：支持地理位置查询","<strong>哈希索引</strong>：基于哈希值的索引"]},{type:"heading",text:"索引优化建议"},{type:"list",items:["<strong>优先满足常用查询</strong>：根据查询频率和排序字段建立索引","<strong>覆盖索引</strong>：索引包含查询所需字段，避免回表","<strong>使用 hint()</strong>：强制使用特定索引进行查询优化","<strong>避免过多索引</strong>：过多索引会影响写入性能","<strong>定期审查</strong>：使用 db.collection.getIndexes() 和 explain() 检查索引使用情况"]}]},{id:"aggregation",title:"聚合框架",content:[{type:"heading",text:"聚合管道"},{type:"paragraph",text:"MongoDB 的聚合框架提供了强大的数据处理能力，通过管道操作符对数据进行转换和计算。"},{type:"code",lang:"javascript",code:'db.orders.aggregate([\n  // $match: 筛选文档\n  { $match: { status: "completed" } },\n\n  // $group: 分组统计\n  {\n    $group: {\n      _id: "$userId",\n      totalAmount: { $sum: "$amount" },\n      count: { $sum: 1 },\n      avgAmount: { $avg: "$amount" }\n    }\n  },\n\n  // $sort: 排序\n  { $sort: { totalAmount: -1 } },\n\n  // $limit: 限制结果数量\n  { $limit: 10 }\n])'},{type:"heading",text:"常用聚合操作符"},{type:"table",headers:["阶段","操作符","说明"],rows:[["$match","筛选条件","过滤文档，类似find()"],["$group","分组统计","按字段分组并计算聚合值"],["$sort","排序","对结果进行排序"],["$limit","限制数量","限制返回文档数量"],["$skip","跳过文档","跳过指定数量的文档"],["$project","字段投影","选择、重命名和转换字段"],["$unwind","展开数组","将数组字段展开为多个文档"],["$lookup","左连接","类似SQL的LEFT JOIN"]]},{type:"heading",text:"聚合表达式"},{type:"code",lang:"javascript",code:'// 数学表达式\n{ $sum: "$price" }      // 求和\n{ $avg: "$price" }      // 平均值\n{ $min: "$price" }      // 最小值\n{ $max: "$price" }      // 最大值\n\n// 条件表达式\n{\n  $cond: {\n    if: { $gte: ["$score", 60] },\n    then: "及格",\n    else: "不及格"\n  }\n}\n\n// 字符串表达式\n{ $concat: ["$firstName", " ", "$lastName"] }  // 字符串拼接\n{ $toLower: "$name" }     // 转小写\n{ $toUpper: "$name" }     // 转大写\n\n// 数组表达式\n{ $size: "$tags" }        // 数组长度\n{ $in: ["mongodb", "$tags"] }  // 是否包含元素'}]},{id:"replication",title:"副本集",content:[{type:"heading",text:"副本集概述"},{type:"paragraph",text:"副本集是一组维护相同数据集的 MongoDB 服务器，提供数据冗余和高可用性。"},{type:"heading",text:"副本集架构"},{type:"list",items:["<strong>Primary（主节点）</strong>：接收所有写操作","<strong>Secondary（从节点）</strong>：从主节点复制数据，提供读操作","<strong>Arbiter（仲裁节点）</strong>：参与选举，不存储数据"]},{type:"heading",text:"部署副本集"},{type:"code",lang:"bash",code:"# 启动三个 MongoDB 实例\nmongod --replSet rs0 --port 27017 --dbpath /data/db1\nmongod --replSet rs0 --port 27018 --dbpath /data/db2\nmongod --replSet rs0 --port 27019 --dbpath /data/db3\n\n# 启动仲裁节点\nmongod --replSet rs0 --port 27020 --dbpath /data/arbiter"},{type:"code",lang:"javascript",code:'// 启动 MongoDB 时指定副本集\nmongod --replSet rs0 --port 27017\n\n// 连接到 MongoDB 后初始化副本集\nrs.initiate({\n  _id: "rs0",\n  members: [\n    { _id: 0, host: "localhost:27017" },\n    { _id: 1, host: "localhost:27018" },\n    { _id: 2, host: "localhost:27019" }\n  ]\n})\n\n// 查看副本集状态\nrs.status()\n\n// 添加成员\nrs.add("localhost:27020")\n\n// 移除成员\nrs.remove("localhost:27020")'},{type:"heading",text:"读写分离"},{type:"code",lang:"javascript",code:'// 设置读偏好（客户端）\n// primary: 只从主节点读（默认）\n// primaryPreferred: 优先主节点\n// secondary: 只从节点读\n// secondaryPreferred: 优先从节点\n// nearest: 读延迟最低的节点\n\ndb.collection.find().readPref("secondary")'},{type:"heading",text:"副本集配置优化"},{type:"list",items:["<strong>优先级 (priority)</strong>：控制节点选举主节点的倾向","<strong>隐藏节点 (hidden)</strong>：用于备份/分析，避免对外提供服务","<strong>投票权 (votes)</strong>：通常设置为1，仲裁节点可设置为0","<strong>Oplog 大小</strong>：在高写入场景下适当增大以减少延迟","<strong>心跳间隔</strong>：默认2秒，可根据网络环境调整"]}]},{id:"sharding",title:"分片与扩展",content:[{type:"heading",text:"分片概述"},{type:"paragraph",text:"分片是 MongoDB 实现水平扩展的核心技术，将数据分散存储在多个服务器上。"},{type:"heading",text:"分片架构组件"},{type:"list",items:["<strong>Shard（分片服务器）</strong>：存储数据分片","<strong>Config Server（配置服务器）</strong>：存储集群元数据","<strong>Mongos（路由服务器）</strong>：请求路由，协调查询"]},{type:"heading",text:"分片键选择"},{type:"paragraph",text:"分片键决定了数据如何分布，选择合适的分片键至关重要。"},{type:"code",lang:"javascript",code:'// 启用分片\nsh.enableSharding("mydb")\n\n// 对集合进行分片\nsh.shardCollection("mydb.users", { userId: 1 })\n\n// 哈希分片（均匀分布）\nsh.shardCollection("mydb.logs", { _id: "hashed" })'},{type:"heading",text:"分片策略"},{type:"list",items:["<strong>范围分片</strong>：基于分片键值的范围分布数据","<strong>哈希分片</strong>：基于分片键哈希值均匀分布数据","<strong>区域分片</strong>：基于地理位置或自定义标签分布数据"]},{type:"heading",text:"分片管理"},{type:"code",lang:"javascript",code:'// 查看分片状态\nsh.status()\n\n// 添加分片服务器\nsh.addShard("rs1/localhost:27021,localhost:27022")\n\n// 重新平衡分片\nsh.startBalancer()\nsh.stopBalancer()\n\n// 查看分片分布\ndb.collection.getShardDistribution()'}]},{id:"transactions",title:"事务",content:[{type:"heading",text:"多文档事务"},{type:"paragraph",text:"MongoDB 4.0+ 支持多文档事务，确保多个文档操作的原子性。"},{type:"code",lang:"javascript",code:'// 启动事务会话\nconst session = db.getMongo().startSession()\n\nsession.startTransaction({\n  readConcern: { level: "snapshot" },\n  writeConcern: { w: "majority" }\n})\n\ntry {\n  // 在事务中执行操作\n  db.accounts.updateOne(\n    { _id: "account1" },\n    { $inc: { balance: -100 } },\n    { session }\n  )\n\n  db.accounts.updateOne(\n    { _id: "account2" },\n    { $inc: { balance: 100 } },\n    { session }\n  )\n\n  // 提交事务\n  session.commitTransaction()\n} catch (error) {\n  // 回滚事务\n  session.abortTransaction()\n} finally {\n  session.endSession()\n}'},{type:"heading",text:"事务限制"},{type:"list",items:["<strong>运行时间限制</strong>：默认60秒，可配置","<strong>数据大小限制</strong>：16MB（WiredTiger缓存大小）","<strong>操作数量限制</strong>：1000个操作","<strong>只读事务不支持</strong>：快照隔离","<strong>分片集群限制</strong>：某些操作不支持"]},{type:"heading",text:"ACID 属性"},{type:"table",headers:["属性","MongoDB实现","说明"],rows:[["原子性(Atomicity)","✓","事务中的操作要么全部成功，要么全部失败"],["一致性(Consistency)","✓","事务前后数据库保持一致状态"],["隔离性(Isolation)","快照隔离","事务间相互隔离，避免脏读、不可重复读、幻读"],["持久性(Durability)","✓","事务提交后数据持久化到磁盘"]]}]},{id:"security",title:"安全配置",content:[{type:"heading",text:"认证与授权"},{type:"code",lang:"javascript",code:'// 启用认证启动\nmongod --auth --keyFile /path/to/keyfile\n\n// 创建管理员用户\nuse admin\ndb.createUser({\n  user: "admin",\n  pwd: "password",\n  roles: ["userAdminAnyDatabase", "dbAdminAnyDatabase", "readWriteAnyDatabase"]\n})\n\n// 创建应用用户\nuse myapp\ndb.createUser({\n  user: "appuser",\n  pwd: "apppassword",\n  roles: ["readWrite"]\n})\n\n// 角色权限说明\n// read: 只读权限\n// readWrite: 读写权限\n// dbAdmin: 数据库管理权限\n// userAdmin: 用户管理权限\n// clusterAdmin: 集群管理权限'},{type:"heading",text:"TLS/SSL 加密"},{type:"code",lang:"bash",code:"# 生成证书\nopenssl req -new -x509 -days 365 -out mongodb.crt -keyout mongodb.key\n\n# 合并证书和私钥\ncat mongodb.key mongodb.crt > mongodb.pem\n\n# 启用 TLS 启动\nmongod --sslMode requireSSL --sslPEMKeyFile mongodb.pem"},{type:"heading",text:"网络安全"},{type:"code",lang:"javascript",code:"// 绑定特定 IP\nmongod --bind_ip 127.0.0.1,192.168.1.100\n\n// 禁用 HTTP 接口\nmongod --nohttpinterface\n\n// 设置最大连接数\nmongod --maxConns 1000"},{type:"heading",text:"审计日志"},{type:"code",lang:"javascript",code:'// 启用审计\nmongod --auditDestination file --auditFormat JSON --auditPath /var/log/mongodb/audit.log\n\n// 审计配置\ndb.createUser({\n  user: "auditor",\n  pwd: "auditpass",\n  roles: ["clusterAdmin"]\n})'}]},{id:"backup-recovery",title:"备份与恢复",content:[{type:"heading",text:"备份策略"},{type:"list",items:["<strong>逻辑备份</strong>：使用 mongoexport/mongoimport，灵活但慢","<strong>物理备份</strong>：直接复制数据文件，快但需要停止服务","<strong>副本集备份</strong>：从从节点备份，不影响主节点","<strong>分片集群备份</strong>：需要备份所有组件"]},{type:"heading",text:"使用 mongodump 备份"},{type:"code",lang:"bash",code:"# 备份整个数据库\nmongodump --db mydb --out /backup/$(date +%Y%m%d)\n\n# 备份特定集合\nmongodump --db mydb --collection users --out /backup/users\n\n# 压缩备份\nmongodump --db mydb --out /backup --gzip\n\n# 远程备份\nmongodump --host mongodb.example.com --port 27017 --db mydb --out /backup"},{type:"heading",text:"使用 mongorestore 恢复"},{type:"code",lang:"bash",code:"# 恢复数据库\nmongorestore --db mydb /backup/mydb\n\n# 恢复到不同数据库\nmongorestore --db newdb /backup/mydb\n\n# 从压缩备份恢复\nmongorestore --gzip --db mydb /backup/mydb\n\n# 恢复特定集合\nmongorestore --db mydb --collection users /backup/mydb/users"},{type:"heading",text:"自动化备份脚本"},{type:"code",lang:"bash",code:'#!/bin/bash\n\n# 备份脚本\nDB_NAME="mydb"\nBACKUP_DIR="/backup"\nDATE=$(date +%Y%m%d_%H%M%S)\n\nmkdir -p $BACKUP_DIR/$DATE\n\n# 执行备份\nmongodump --db=$DB_NAME --out=$BACKUP_DIR/$DATE --gzip\n\n# 清理7天前的备份\nfind $BACKUP_DIR -type d -mtime +7 -exec rm -rf {} +\n\necho "Backup completed: $BACKUP_DIR/$DATE"'}]},{id:"monitoring",title:"监控与维护",content:[{type:"heading",text:"监控指标"},{type:"list",items:["<strong>连接数</strong>：当前活跃连接数量","<strong>操作统计</strong>：读写操作的频率和延迟","<strong>内存使用</strong>：WiredTiger缓存和系统内存","<strong>磁盘I/O</strong>：读写操作的磁盘性能","<strong>副本集状态</strong>：主从同步延迟和健康状态","<strong>慢查询日志</strong>：识别性能瓶颈"]},{type:"heading",text:"数据库状态检查"},{type:"code",lang:"javascript",code:"// 服务器状态\ndb.serverStatus()\n\n// 数据库统计\ndb.stats()\n\n// 集合统计\ndb.collection.stats()\n\n// 副本集状态\nrs.status()\n\n// 分片状态\nsh.status()"},{type:"heading",text:"性能分析"},{type:"code",lang:"javascript",code:'// 启用性能分析器\ndb.setProfilingLevel(2, { slowms: 100 })\n\n// 查看慢查询\ndb.system.profile.find().sort({ ts: -1 }).limit(5)\n\n// 解释查询执行计划\ndb.collection.find({ field: "value" }).explain("executionStats")\n\n// 查看当前操作\ndb.currentOp()'},{type:"heading",text:"日志管理"},{type:"code",lang:"bash",code:'# 日志轮转\nmongod --logpath /var/log/mongodb/mongod.log \\\n       --logRotate reopen\n\n# 日志级别设置\ndb.setLogLevel(1, "query")\ndb.setLogLevel(0, "query")  # 恢复默认'}]},{id:"modeling",title:"数据建模",content:[{type:"heading",text:"文档设计原则"},{type:"list",items:["<strong>内嵌 vs 引用</strong>：根据访问模式选择","<strong>读写比例</strong>：读多场景优先内嵌","<strong>数据局部性</strong>：相关数据放在一起","<strong>原子性需求</strong>：需要事务的数据考虑引用","<strong>文档大小限制</strong>：单个文档不超过16MB"]},{type:"heading",text:"内嵌文档模式"},{type:"code",lang:"javascript",code:'// 用户资料（内嵌地址）\n{\n  _id: ObjectId("..."),\n  name: "张三",\n  email: "zhangsan@example.com",\n  addresses: [\n    {\n      type: "home",\n      street: "北京市朝阳区",\n      city: "北京",\n      country: "中国"\n    },\n    {\n      type: "work",\n      street: "北京市海淀区",\n      city: "北京",\n      country: "中国"\n    }\n  ]\n}\n\n// 博客文章（内嵌评论）\n{\n  _id: ObjectId("..."),\n  title: "MongoDB 最佳实践",\n  content: "...",\n  author: {\n    name: "李四",\n    email: "lisi@example.com"\n  },\n  comments: [\n    {\n      author: "王五",\n      content: "很好",\n      createdAt: ISODate("2023-01-01")\n    }\n  ]\n}'},{type:"heading",text:"引用模式"},{type:"code",lang:"javascript",code:'// 用户集合\n{\n  _id: ObjectId("user1"),\n  name: "张三",\n  email: "zhangsan@example.com"\n}\n\n// 订单集合（引用用户）\n{\n  _id: ObjectId("order1"),\n  userId: ObjectId("user1"),  // 引用用户ID\n  items: [...],\n  total: 100\n}\n\n// 使用 $lookup 进行关联查询\ndb.orders.aggregate([\n  {\n    $lookup: {\n      from: "users",\n      localField: "userId",\n      foreignField: "_id",\n      as: "user"\n    }\n  }\n])'},{type:"heading",text:"数据建模最佳实践"},{type:"list",items:["<strong>优先考虑读取模式</strong>：设计时优先考虑应用的主要查询模式","<strong>避免过度规范化</strong>：MongoDB 不需要严格的规范化设计","<strong>使用合适的分片键</strong>：为分片集群选择合适的分片键","<strong>预留字段</strong>：为未来可能的变化预留一些字段","<strong>定期审查</strong>：随着应用发展定期审查数据模型"]}]},{id:"advanced-features",title:"高级特性",content:[{type:"heading",text:"变更流 (Change Streams)"},{type:"paragraph",text:"变更流允许应用程序监听数据库的实时变更，实现事件驱动架构。"},{type:"code",lang:"javascript",code:"// 监听集合变更\nconst changeStream = db.collection.watch()\n\nchangeStream.on('change', (change) => {\n  console.log('变更类型:', change.operationType)\n  console.log('文档ID:', change.documentKey._id)\n\n  if (change.operationType === 'insert') {\n    console.log('新文档:', change.fullDocument)\n  }\n})\n\n// 监听特定操作\ndb.collection.watch([\n  { $match: { operationType: { $in: ['insert', 'update'] } } }\n])\n\n// 带过滤的变更流\ndb.collection.watch([\n  {\n    $match: {\n      $and: [\n        { operationType: 'update' },\n        { 'updateDescription.updatedFields.status': { $exists: true } }\n      ]\n    }\n  }\n])"},{type:"heading",text:"地理空间查询"},{type:"code",lang:"javascript",code:'// 创建地理空间索引\ndb.places.createIndex({ location: "2dsphere" })\n\n// 插入地理位置数据\ndb.places.insertMany([\n  {\n    name: "天安门",\n    location: {\n      type: "Point",\n      coordinates: [116.3974, 39.9093]  // [经度, 纬度]\n    }\n  },\n  {\n    name: "故宫",\n    location: {\n      type: "Point",\n      coordinates: [116.3974, 39.9163]\n    }\n  }\n])\n\n// 附近查询\ndb.places.find({\n  location: {\n    $near: {\n      $geometry: {\n        type: "Point",\n        coordinates: [116.4074, 39.9093]\n      },\n      $maxDistance: 1000  // 米\n    }\n  }\n})\n\n// 多边形查询\ndb.places.find({\n  location: {\n    $geoWithin: {\n      $geometry: {\n        type: "Polygon",\n        coordinates: [[\n          [116.3, 39.8],\n          [116.5, 39.8],\n          [116.5, 40.0],\n          [116.3, 40.0],\n          [116.3, 39.8]\n        ]]\n      }\n    }\n  }\n})'},{type:"heading",text:"全文搜索"},{type:"code",lang:"javascript",code:'// 创建文本索引\ndb.articles.createIndex({ title: "text", content: "text" })\n\n// 文本搜索\ndb.articles.find({\n  $text: { $search: "MongoDB 教程" }\n})\n\n// 带分数的文本搜索\ndb.articles.find(\n  { $text: { $search: "MongoDB" } },\n  { score: { $meta: "textScore" } }\n).sort({ score: { $meta: "textScore" } })\n\n// 排除特定词\ndb.articles.find({\n  $text: { $search: "MongoDB -MySQL" }\n})'},{type:"heading",text:"GridFS 大文件存储"},{type:"code",lang:"javascript",code:"// 存储大文件\nconst fs = require('fs')\nconst mongo = require('mongodb')\n\n// 连接数据库\nconst client = await mongo.MongoClient.connect('mongodb://localhost:27017')\nconst db = client.db('mydb')\nconst bucket = new mongo.GridFSBucket(db)\n\n// 上传文件\nconst uploadStream = bucket.openUploadStream('large-file.pdf')\nfs.createReadStream('./large-file.pdf').pipe(uploadStream)\n\n// 下载文件\nconst downloadStream = bucket.openDownloadStreamByName('large-file.pdf')\ndownloadStream.pipe(fs.createWriteStream('./downloaded-file.pdf'))"}]}]},mysql:{name:"MySQL",icon:"M",color:"from-blue-400 to-blue-600",chapters:[{id:"intro",title:"MySQL 简介",content:[{type:"heading",text:"什么是 MySQL"},{type:"paragraph",text:"MySQL 是最流行的开源关系型数据库管理系统，由 Oracle 公司维护。MySQL 8.0 是当前主流版本，引入了窗口函数、CTE、JSON增强等大量新特性。"},{type:"heading",text:"核心特点"},{type:"list",items:["<strong>关系型数据库</strong>：基于表结构的数据存储，支持完整的 SQL 标准","<strong>ACID 事务</strong>：InnoDB 引擎保证数据一致性和完整性","<strong>高性能</strong>：优化的查询引擎、索引系统和查询缓存","<strong>可扩展性</strong>：支持读写分离、分库分表和集群部署","<strong>丰富的生态</strong>：广泛的工具、驱动和社区支持","<strong>多存储引擎</strong>：InnoDB（默认）、MyISAM、Memory、CSV 等"]},{type:"heading",text:"MySQL 8.0 新特性"},{type:"list",items:["<strong>窗口函数</strong>：支持 ROW_NUMBER()、RANK()、DENSE_RANK() 等","<strong>公用表表达式 (CTE)</strong>：支持递归和非递归 CTE","<strong>JSON 增强</strong>：JSON 表函数、JSON 聚合函数、部分索引更新","<strong>降序索引</strong>：真正支持降序扫描，提升 ORDER BY DESC 性能","<strong>不可见索引</strong>：索引维护不影响查询，便于测试和优化","<strong>直方图统计</strong>：改进查询优化器的统计信息收集","<strong>资源组</strong>：精细控制资源使用，支持多租户隔离","<strong>认证增强</strong>：默认使用 caching_sha2_password，提升安全性"]}]},{id:"architecture",title:"架构与存储引擎",content:[{type:"heading",text:"MySQL 架构"},{type:"paragraph",text:"MySQL 采用分层架构设计："},{type:"list",items:["<strong>连接层</strong>：负责客户端连接、身份认证、线程管理","<strong>服务层</strong>：SQL 接口、解析器、优化器、缓存","<strong>存储引擎层</strong>：负责数据的存储和提取","<strong>存储层</strong>：文件系统、数据文件、日志文件"]},{type:"heading",text:"存储引擎对比"},{type:"table",headers:["特性","InnoDB","MyISAM","Memory"],rows:[["事务支持","✓","✗","✗"],["外键约束","✓","✗","✗"],["行级锁","✓","✗","✓"],["表级锁","✓","✓","✓"],["崩溃恢复","✓","✗","✗"],["支持外键","✓","✗","✗"],["适用场景","OLTP","读密集","临时表"]]},{type:"heading",text:"InnoDB 引擎深入"},{type:"list",items:["<strong>缓冲池 (Buffer Pool)</strong>：缓存数据页和索引页，默认 128MB","<strong>重做日志 (Redo Log)</strong>：实现崩溃恢复和持久性","<strong>撤销日志 (Undo Log)</strong>：支持 MVCC 和事务回滚","<strong>更改缓冲 (Change Buffer)</strong>：缓存辅助索引的变更","<strong>自适应哈希索引</strong>：自动为热点数据创建哈希索引"]},{type:"heading",text:"企业级配置示例"},{type:"code",lang:"bash",code:"[mysqld]\n# 基础配置\nport = 3306\ndatadir = /var/lib/mysql\nsocket = /var/lib/mysql/mysql.sock\n\n# 字符集 (推荐 utf8mb4)\ncharacter-set-server = utf8mb4\ncollation-server = utf8mb4_unicode_ci\n\n# 连接配置\nmax_connections = 500\nmax_connect_errors = 10000\nwait_timeout = 28800\ninteractive_timeout = 28800\n\n# InnoDB 内存配置 (物理内存的 70-80%)\ninnodb_buffer_pool_size = 4G\ninnodb_buffer_pool_instances = 4\ninnodb_log_file_size = 512M\ninnodb_log_buffer_size = 16M\n\n# InnoDB I/O 配置\ninnodb_io_capacity = 2000\ninnodb_io_capacity_max = 4000\ninnodb_flush_method = O_DIRECT\n\n# InnoDB 并发配置\ninnodb_read_io_threads = 8\ninnodb_write_io_threads = 8\ninnodb_purge_threads = 4\ninnodb_page_cleaners = 4\n\n# 事务配置\ninnodb_flush_log_at_trx_commit = 1  # 安全性最高\nsync_binlog = 1                     # 双一配置，保证安全\n\n# 慢查询日志\nslow_query_log = 1\nslow_query_log_file = /var/log/mysql/slow.log\nlong_query_time = 2\n\n# Binlog 配置\nlog_bin = mysql-bin\nbinlog_format = ROW\nbinlog_row_image = FULL\nexpire_logs_days = 7"}]},{id:"index-optimization",title:"索引优化",content:[{type:"heading",text:"索引类型"},{type:"list",items:["<strong>主键索引 (PRIMARY)</strong>：唯一标识，聚簇索引","<strong>唯一索引 (UNIQUE)</strong>：保证值唯一","<strong>普通索引 (INDEX)</strong>：加速查询","<strong>联合索引</strong>：多个字段组合","<strong>全文索引 (FULLTEXT)</strong>：文本搜索","<strong>空间索引 (SPATIAL)</strong>：地理数据查询"]},{type:"heading",text:"索引设计原则"},{type:"list",items:["<strong>选择合适的列</strong>：WHERE、ORDER BY、JOIN 的列","<strong>最左前缀原则</strong>：联合索引按最左优先匹配","<strong>区分度高</strong>：选择区分度高的列建立索引","<strong>避免过多索引</strong>：索引会增加写操作开销","<strong>索引列不为 NULL</strong>：NULL 值影响索引效率"]},{type:"heading",text:"联合索引与最左前缀"},{type:"code",lang:"sql",code:"-- 创建联合索引 (name, age, city)\nCREATE INDEX idx_user_info ON users(name, age, city);\n\n-- 能使用索引的查询\nSELECT * FROM users WHERE name = 'Tom';                    -- ✓\nSELECT * FROM users WHERE name = 'Tom' AND age = 20;        -- ✓\nSELECT * FROM users WHERE name = 'Tom' AND age = 20 AND city = 'Beijing'; -- ✓\n\n-- 不能使用索引的查询 (违反最左前缀)\nSELECT * FROM users WHERE age = 20;                         -- ✗\nSELECT * FROM users WHERE city = 'Beijing';                  -- ✗\nSELECT * FROM users WHERE age = 20 AND city = 'Beijing';     -- ✗\n\n-- 使用索引排序\nSELECT * FROM users WHERE name = 'Tom' ORDER BY age;         -- ✓\nSELECT * FROM users WHERE name = 'Tom' ORDER BY age, city;   -- ✓\nSELECT * FROM users WHERE name = 'Tom' ORDER BY city;        -- ✗ (跳过age)"},{type:"heading",text:"索引下推 (ICP)"},{type:"paragraph",text:"MySQL 5.6+ 引入的索引下推优化，将 WHERE 条件尽可能下推到存储引擎层过滤，减少回表次数。"},{type:"code",lang:"sql",code:"-- 假设联合索引 (name, age)\nSELECT * FROM users WHERE name LIKE 'Tom%' AND age > 20;\n\n-- 无 ICP: 存储引擎返回所有 name 开头是 Tom 的记录，Server 层过滤 age\n-- 有 ICP: 存储引擎直接过滤 age > 20，只返回符合条件的数据"},{type:"heading",text:"覆盖索引"},{type:"paragraph",text:"查询所需字段都在索引中，无需回表，大幅提升性能。"},{type:"code",lang:"sql",code:"-- 联合索引 (name, age, email)\nSELECT name, age, email FROM users WHERE name = 'Tom';\n-- 索引已包含所需字段，无需回表"},{type:"heading",text:"索引失效场景"},{type:"list",items:["<strong>使用函数</strong>：WHERE YEAR(create_time) = 2024","<strong>隐式转换</strong>：字符串列用数字查询","<strong>LIKE 前缀通配符</strong>：WHERE name LIKE '%Tom'","<strong>OR 条件</strong>：未索引的列使用 OR","<strong>不等于</strong>：WHERE age != 18（可走索引但效率低）","<strong>IS NULL / IS NOT NULL</strong>：视情况而定"]},{type:"heading",text:"索引分析工具"},{type:"code",lang:"sql",code:"-- 查看索引使用情况\nSHOW INDEX FROM users;\n\n-- 分析索引选择性（越接近1越好）\nSELECT COUNT(DISTINCT name) / COUNT(*) FROM users;\n\n-- 查看索引基数\nANALYZE TABLE users;\nSHOW INDEX FROM users;\n\n-- 系统库查看索引统计\nSELECT * FROM mysql.innodb_index_stats;"}]},{id:"query-optimization",title:"查询优化",content:[{type:"heading",text:"EXPLAIN 执行计划分析"},{type:"paragraph",text:"使用 EXPLAIN 分析 SQL 执行计划，优化查询性能。"},{type:"code",lang:"sql",code:"EXPLAIN SELECT * FROM users WHERE name = 'Tom';\n\n+----+-------------+-------+------+---------------+------+---------+-------+------+-------+\n| id | select_type | table | type | possible_keys | key  | key_len | ref   | rows | Extra |\n+----+-------------+-------+------+---------------+------+---------+-------+------+-------+\n\n# 关键字段说明\n# type: 访问类型，性能从好到差：system > const > eq_ref > ref > range > index > ALL\n# key: 实际使用的索引\n# rows: 预估扫描行数，越少越好\n# Extra: 额外信息\n#   - Using index: 覆盖索引，好！\n#   - Using filesort: 文件排序，需要优化\n#   - Using temporary: 使用临时表，需要优化"},{type:"heading",text:"SQL 编写最佳实践"},{type:"list",items:["<strong>避免 SELECT *</strong>：只查询需要的列，减少网络传输和内存占用","<strong>合理使用 LIMIT</strong>：分页查询使用 LIMIT，避免大结果集","<strong>批量操作</strong>：使用批量插入代替单条插入","<strong>避免子查询</strong>：复杂子查询改用 JOIN","<strong>使用 UNION ALL</strong>：不需要去重时用 UNION ALL 代替 UNION","<strong>使用绑定变量</strong>：预编译语句，防止 SQL 注入"]},{type:"heading",text:"子查询优化"},{type:"code",lang:"sql",code:"-- 不推荐：子查询\nSELECT * FROM users WHERE id IN (SELECT user_id FROM orders WHERE amount > 1000);\n\n-- 推荐：改写为 JOIN\nSELECT u.* FROM users u\nINNER JOIN orders o ON u.id = o.user_id\nWHERE o.amount > 1000;\n\n-- 或者使用 EXISTS (更高效)\nSELECT * FROM users u\nWHERE EXISTS (\n  SELECT 1 FROM orders o\n  WHERE o.user_id = u.id AND o.amount > 1000\n);"},{type:"heading",text:"分页优化"},{type:"code",lang:"sql",code:"-- 传统分页（深分页性能差）\nSELECT * FROM orders ORDER BY id LIMIT 1000000, 20;\n\n-- 优化方案1：使用上次最大ID\nSELECT * FROM orders WHERE id > 1000000 ORDER BY id LIMIT 20;\n\n-- 优化方案2：延迟关联\nSELECT o.* FROM orders o\nINNER JOIN (SELECT id FROM orders ORDER BY id LIMIT 1000000, 20) t\nON o.id = t.id;"},{type:"heading",text:"慢查询分析"},{type:"code",lang:"sql",code:"-- 开启慢查询日志\nSET GLOBAL slow_query_log = 'ON';\nSET GLOBAL long_query_time = 2;\n\n-- 查看 slow_query_log 配置\nSHOW VARIABLES LIKE '%slow_query%';\n\n-- 分析慢查询日志\nmysqldumpslow -s t -t 10 /var/log/mysql/slow.log\n\n-- 使用 pt-query-digest 分析\npt-query-digest /var/log/mysql/slow.log"}]},{id:"transaction",title:"事务与锁",content:[{type:"heading",text:"事务隔离级别"},{type:"table",headers:["隔离级别","脏读","不可重复读","幻读","说明"],rows:[["READ UNCOMMITTED","✓","✓","✓","读未提交，几乎不用"],["READ COMMITTED","✗","✓","✓","读已提交，Oracle 默认"],["REPEATABLE READ","✗","✗","✓","可重复读，MySQL 默认"],["SERIALIZABLE","✗","✗","✗","串行化，最高隔离"]]},{type:"heading",text:"MVCC 多版本并发控制"},{type:"paragraph",text:"InnoDB 通过 MVCC 实现非锁定读，允许读写操作并发执行。"},{type:"list",items:["<strong>Read View</strong>：事务启动时创建的快照视图","<strong>Undo Log</strong>：存储数据的历史版本","<strong>隐藏列</strong>：DB_TRX_ID、DB_ROLL_PTR、DB_ROW_ID"]},{type:"heading",text:"锁机制"},{type:"list",items:["<strong>共享锁 (S Lock)</strong>：读锁，允许多个事务同时读取","<strong>排他锁 (X Lock)</strong>：写锁，只允许一个事务修改","<strong>意向锁</strong>：表级锁，表明将来要对行加锁","<strong>间隙锁</strong>：锁定索引记录之间的间隙，防止幻读","<strong>临键锁</strong>：记录锁 + 间隙锁"]},{type:"heading",text:"锁等待与死锁"},{type:"code",lang:"sql",code:"-- 查看锁等待情况\nSELECT * FROM information_schema.innodb_locks;\nSELECT * FROM information_schema.innodb_lock_waits;\nSELECT * FROM information_schema.innodb_trx;\n\n-- 查看死锁日志\nSHOW ENGINE INNODB STATUS;\n\n-- 设置锁等待超时\nSET SESSION innodb_lock_wait_timeout = 50;\n\n-- 死锁检测（默认开启）\nSET GLOBAL innodb_deadlock_detect = ON;"},{type:"heading",text:"事务最佳实践"},{type:"list",items:["<strong>事务要短</strong>：避免长事务，减少锁持有时间","<strong>尽早提交</strong>：事务完成后立即提交","<strong>避免大事务</strong>：大量更新分批执行","<strong>设置合理隔离级别</strong>：默认 REPEATABLE READ","<strong>注意锁顺序</strong>：多表操作按固定顺序访问"]}]},{id:"replication",title:"主从复制",content:[{type:"heading",text:"复制原理"},{type:"list",items:["<strong>Binlog</strong>：主库记录所有数据变更的二进制日志","<strong>I/O Thread</strong>：从库请求并接收主库的 Binlog","<strong>Relay Log</strong>：从库存储 Binlog 的中继日志","<strong>SQL Thread</strong>：从库重放中继日志中的变更"]},{type:"heading",text:"Binlog 格式"},{type:"table",headers:["格式","优点","缺点","适用场景"],rows:[["STATEMENT","日志小，节省空间","可能不一致，函数可能有问题","简单查询"],["ROW","最安全，数据一致","日志大，无法从日志看具体语句","生产环境推荐"],["MIXED","折中方案","复杂场景仍可能有问题","一般场景"]]},{type:"heading",text:"GTID 复制"},{type:"paragraph",text:"GTID (Global Transaction ID) 是 MySQL 5.6 引入的全局事务 ID，简化主从复制管理。"},{type:"code",lang:"bash",code:"[mysqld]\n# 启用 GTID\ngtid_mode = ON\nenforce_gtid_consistency = ON\n\n# 启用 binlog\nlog_bin = mysql-bin\nbinlog_format = ROW\nbinlog_row_image = FULL"},{type:"heading",text:"主从配置示例"},{type:"code",lang:"sql",code:"-- 主库配置\nCHANGE MASTER TO\n  MASTER_HOST='192.168.1.10',\n  MASTER_USER='repl',\n  MASTER_PASSWORD='password',\n  MASTER_PORT=3306,\n  MASTER_AUTO_POSITION=1;  -- GTID 模式\n\n-- 启动从库复制\nSTART SLAVE;\n\n-- 查看从库状态\nSHOW SLAVE STATUS\\G\n\n-- 关键指标\n-- Slave_IO_Running: Yes\n-- Slave_SQL_Running: Yes\n-- Seconds_Behind_Master: 延迟秒数（0表示无延迟）"},{type:"heading",text:"并行复制"},{type:"paragraph",text:"MySQL 5.7+ 支持并行复制，提升从库应用速度。"},{type:"code",lang:"sql",code:"-- 设置并行复制模式\nSET GLOBAL slave_parallel_type = 'LOGICAL_CLOCK';\nSET GLOBAL slave_parallel_workers = 4;  -- 并行线程数"}]},{id:"sharding",title:"分库分表",content:[{type:"heading",text:"分库分表策略"},{type:"list",items:["<strong>垂直分库</strong>：按业务模块拆分，不同库不同业务","<strong>垂直分表</strong>：按字段使用频率拆分，热字段与冷字段分离","<strong>水平分库</strong>：同一业务数据分散到多个库","<strong>水平分表</strong>：同一表数据分散到多个表"]},{type:"heading",text:"分片策略"},{type:"table",headers:["策略","说明","优点","缺点"],rows:[["Range","按范围分片","查询范围数据快","数据分布不均"],["Hash","哈希取模","数据均匀分布","范围查询需扫表"],["一致性Hash","解决扩容问题","减少迁移量","实现复杂"],["地理位置","按区域分片","就近访问","热点问题"]]},{type:"heading",text:"分库分表中间件"},{type:"list",items:["<strong>ShardingSphere</strong>：Apache 开源，功能完善","<strong>Mycat</strong>：老牌中间件，社区活跃","<strong>Vitess</strong>：YouTube 开源，云原生","<strong>cobar</strong>：阿里开源，已停止维护"]},{type:"heading",text:"分库分表问题"},{type:"list",items:["<strong>分布式事务</strong>：跨库事务一致性难保证","<strong>跨库 JOIN</strong>：需要应用层组装或使用 Elasticsearch","<strong>分页排序</strong>：需要先查询每个分片再聚合","<strong>主键生成</strong>：需要分布式 ID 生成方案","<strong>数据迁移</strong>：扩容时数据迁移复杂"]}]},{id:"backup-recovery",title:"备份与恢复",content:[{type:"heading",text:"备份方式"},{type:"table",headers:["方式","工具","优点","缺点"],rows:[["逻辑备份","mysqldump","跨平台、可编辑","速度慢、恢复慢"],["物理备份","xtrabackup","速度快、支持增量","文件格式依赖平台"],["Binlog","mysqlbinlog","点时间恢复","需要基础备份"]]},{type:"heading",text:"mysqldump 备份"},{type:"code",lang:"bash",code:"# 全库备份\nmysqldump -u root -p --all-databases --single-transaction --master-data=2 > all.sql\n\n# 单库备份\nmysqldump -u root -p --databases mydb > mydb.sql\n\n# 单表备份\nmysqldump -u root -p mydb users > users.sql\n\n# 压缩备份\nmysqldump -u root -p --all-databases | gzip > all.sql.gz\n\n# 关键参数说明\n# --single-transaction: 一致性读，不锁表 (InnoDB)\n# --master-data=2: 记录 binlog 位置\n# --quick: 逐行导出，避免内存溢出\n# --routines: 导出存储过程和函数\n# --triggers: 导出触发器\n# --events: 导出事件"},{type:"heading",text:"XtraBackup 备份"},{type:"code",lang:"bash",code:"# 全量备份\nxtrabackup --backup --target-dir=/backup/full \\\n  --user=root --password=password\n\n# 增量备份\nxtrabackup --backup --target-dir=/backup/inc1 \\\n  --incremental-basedir=/backup/full\n\n# 准备备份\nxtrabackup --prepare --target-dir=/backup/full\n\n# 恢复\nxtrabackup --copy-back --target-dir=/backup/full"},{type:"heading",text:"Binlog 恢复"},{type:"code",lang:"bash",code:'# 查看 binlog 内容\nmysqlbinlog --base64-output=DECODE-ROWS -v mysql-bin.000001\n\n# 指定时间恢复\nmysqlbinlog --start-datetime="2024-01-01 00:00:00" \\\n            --stop-datetime="2024-01-01 23:59:59" \\\n            mysql-bin.000001 | mysql -u root -p\n\n# 指定位置恢复\nmysqlbinlog --start-position=1000 \\\n            --stop-position=2000 \\\n            mysql-bin.000001 | mysql -u root -p'}]},{id:"monitoring",title:"监控与运维",content:[{type:"heading",text:"关键监控指标"},{type:"list",items:["<strong>QPS/TPS</strong>：每秒查询/事务数","<strong>连接数</strong>：当前活跃连接数","<strong>慢查询</strong：超过阈值的查询数量","<strong>缓冲池命中率</strong>：理想值 > 99%","<strong>磁盘 I/O</strong>：读写 IOPS 和延迟","<strong>主从延迟</strong>：Seconds_Behind_Master","<strong>死锁</strong>：死锁发生频率"]},{type:"heading",text:"性能视图 (Performance Schema)"},{type:"code",lang:"sql",code:"-- 启用 Performance Schema\nUPDATE performance_schema.setup_instruments\nSET ENABLED = 'YES', TIMED = 'YES'\nWHERE NAME LIKE '%statement/%';\n\n-- 查看当前正在执行的 SQL\nSELECT * FROM performance_schema.events_statements_current;\n\n-- 查看历史慢查询\nSELECT * FROM performance_schema.events_statements_history_long\nORDER BY TIMER_WAIT DESC LIMIT 10;\n\n-- 查看文件 I/O 统计\nSELECT * FROM performance_schema.file_summary_by_instance;"},{type:"heading",text:"系统库查询"},{type:"code",lang:"sql",code:"-- 服务器状态信息\nSHOW STATUS;\nSHOW STATUS LIKE 'Threads%';\nSHOW STATUS LIKE 'Questions';\n\n-- InnoDB 状态\nSHOW ENGINE INNODB STATUS\\G\n\n-- 表统计信息\nSELECT * FROM information_schema.tables\nWHERE TABLE_SCHEMA = 'mydb';"}]}]},docker:{name:"Docker",icon:"D",color:"from-cyan-400 to-cyan-600",chapters:[{id:"intro",title:"Docker 简介",content:[{type:"heading",text:"什么是 Docker"},{type:"paragraph",text:"Docker 是一个开源的容器化平台，使用 Linux 容器技术将应用程序及其依赖项打包成轻量级、可移植的容器。"},{type:"heading",text:"核心概念"},{type:"list",items:["<strong>镜像 (Image)</strong>：只读的应用模板，包含运行应用所需的一切","<strong>容器 (Container)</strong>：镜像的运行实例，隔离的运行环境","<strong>仓库 (Registry)</strong>：存储和分发镜像的服务，如 Docker Hub","<strong>Dockerfile</strong>：构建镜像的脚本文件","<strong>Compose</strong>：定义和运行多容器应用的工具"]},{type:"heading",text:"Docker vs 虚拟机"},{type:"table",headers:["特性","Docker 容器","虚拟机"],rows:[["启动速度","秒级","分钟级"],["内存占用","MB 级","GB 级"],["隔离性","进程级","系统级"],["性能","接近原生","有损耗"],["可移植性","强","弱"]]}]},{id:"installation",title:"安装与配置",content:[{type:"heading",text:"Linux 安装"},{type:"code",lang:"bash",code:'# Ubuntu/Debian 安装\n# 更新包索引\nsudo apt-get update\n\n# 安装依赖\nsudo apt-get install ca-certificates curl gnupg lsb-release\n\n# 添加 Docker 官方 GPG 密钥\nsudo mkdir -p /etc/apt/keyrings\ncurl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /etc/apt/keyrings/docker.gpg\n\n# 添加仓库\necho \\\n  "deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu \\\n  $(lsb_release -cs) stable" | sudo tee /etc/apt/sources.list.d/docker.list > /dev/null\n\n# 安装 Docker Engine\nsudo apt-get update\nsudo apt-get install docker-ce docker-ce-cli containerd.io docker-compose-plugin\n\n# 启动 Docker\nsudo systemctl start docker\nsudo systemctl enable docker\n\n# 验证安装\nsudo docker run hello-world'},{type:"heading",text:"配置国内镜像加速"},{type:"code",lang:"bash",code:'# 编辑 Docker 配置\nsudo vim /etc/docker/daemon.json\n\n# 添加以下内容\n{\n  "registry-mirrors": [\n    "https://docker.mirrors.ustc.edu.cn",\n    "https://hub-mirror.c.163.com",\n    "https://mirror.ccs.tencentyun.com"\n  ],\n  "log-driver": "json-file",\n  "log-opts": {\n    "max-size": "100m",\n    "max-file": "3"\n  },\n  "storage-driver": "overlay2"\n}\n\n# 重启 Docker\nsudo systemctl daemon-reload\nsudo systemctl restart docker'},{type:"heading",text:"用户权限配置"},{type:"code",lang:"bash",code:"# 将用户添加到 docker 组，避免每次使用 sudo\nsudo usermod -aG docker $USER\n\n# 重新登录或执行\nnewgrp docker\n\n# 验证（无需 sudo）\ndocker ps"}]},{id:"dockerfile",title:"Dockerfile 最佳实践",content:[{type:"heading",text:"Dockerfile 基础指令"},{type:"code",lang:"dockerfile",code:'# 基础镜像\nFROM ubuntu:22.04\n\n# 维护者信息\nLABEL maintainer="your-email@example.com"\n\n# 设置工作目录\nWORKDIR /app\n\n# 复制依赖文件\nCOPY package*.json ./\n\n# 安装依赖\nRUN npm install\n\n# 复制应用代码\nCOPY . .\n\n# 暴露端口\nEXPOSE 3000\n\n# 环境变量\nENV NODE_ENV=production\n\n# 健康检查\nHEALTHCHECK --interval=30s --timeout=3s \\\n  CMD curl -f http://localhost:3000/health || exit 1\n\n# 启动命令\nCMD ["node", "server.js"]'},{type:"heading",text:"多阶段构建"},{type:"code",lang:"dockerfile",code:'# 构建阶段\nFROM node:18-alpine AS builder\n\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci\nCOPY . .\nRUN npm run build\n\n# 生产阶段\nFROM node:18-alpine AS production\n\nWORKDIR /app\nCOPY --from=builder /app/dist ./dist\nCOPY --from=builder /app/node_modules ./node_modules\nCOPY package*.json ./\n\nENV NODE_ENV=production\n\nEXPOSE 3000\nCMD ["node", "dist/server.js"]'},{type:"heading",text:"优化技巧"},{type:"list",items:["<strong>使用 alpine 镜像</strong>：体积更小","<strong>合并 RUN 指令</strong>：减少镜像层数","<strong>利用构建缓存</strong>：不常变化的指令放前面","<strong>使用 .dockerignore</strong>：排除不必要的文件","<strong>多阶段构建</strong>：减小最终镜像体积","<strong>最小化层</strong>：RUN apt-get update && apt-get install -y && rm -rf /var/lib/apt/lists/*"]},{type:"heading",text:".dockerignore 示例"},{type:"code",lang:"text",code:"node_modules\nnpm-debug.log\n.git\n.gitignore\n.env\n.env.local\nREADME.md\n.vscode\n.idea\n*.log\ncoverage\ndist"}]},{id:"docker-compose",title:"Docker Compose",content:[{type:"heading",text:"Compose 基础"},{type:"code",lang:"yaml",code:'version: \'3.8\'\n\nservices:\n  # 应用服务\n  app:\n    build:\n      context: .\n      dockerfile: Dockerfile\n    container_name: myapp\n    restart: always\n    ports:\n      - "3000:3000"\n    environment:\n      - NODE_ENV=production\n      - DB_HOST=mysql\n    env_file:\n      - .env\n    networks:\n      - app-network\n    depends_on:\n      - mysql\n      - redis\n    volumes:\n      - ./logs:/app/logs\n    healthcheck:\n      test: ["CMD", "curl", "-f", "http://localhost:3000/health"]\n      interval: 30s\n      timeout: 10s\n      retries: 3\n\n  # MySQL 服务\n  mysql:\n    image: mysql:8.0\n    container_name: mysql\n    restart: always\n    environment:\n      MYSQL_ROOT_PASSWORD: ${MYSQL_ROOT_PASSWORD}\n      MYSQL_DATABASE: myapp\n    ports:\n      - "3306:3306"\n    volumes:\n      - mysql-data:/var/lib/mysql\n      - ./init.sql:/docker-entrypoint-initdb.d/init.sql\n    networks:\n      - app-network\n    command: --default-authentication-plugin=mysql_native_password\n\n  # Redis 服务\n  redis:\n    image: redis:7-alpine\n    container_name: redis\n    restart: always\n    ports:\n      - "6379:6379"\n    volumes:\n      - redis-data:/data\n    networks:\n      - app-network\n    command: redis-server --appendonly yes\n\n  # Nginx 反向代理\n  nginx:\n    image: nginx:alpine\n    container_name: nginx\n    restart: always\n    ports:\n      - "80:80"\n      - "443:443"\n    volumes:\n      - ./nginx.conf:/etc/nginx/nginx.conf:ro\n      - ./ssl:/etc/nginx/ssl:ro\n    networks:\n      - app-network\n    depends_on:\n      - app\n\nnetworks:\n  app-network:\n    driver: bridge\n\nvolumes:\n  mysql-data:\n  redis-data:'},{type:"heading",text:"常用命令"},{type:"code",lang:"bash",code:"# 启动所有服务\ndocker-compose up -d\n\n# 停止所有服务\ndocker-compose down\n\n# 查看服务状态\ndocker-compose ps\n\n# 查看服务日志\ndocker-compose logs -f app\n\n# 重启服务\ndocker-compose restart app\n\n# 进入容器\ndocker-compose exec app bash\n\n# 查看资源使用\ndocker-compose top\n\n# 扩展服务\ndocker-compose up -d --scale app=3"}]},{id:"network",title:"网络管理",content:[{type:"heading",text:"网络驱动类型"},{type:"table",headers:["驱动","说明","使用场景"],rows:[["bridge","默认桥接网络","单机多容器通信"],["host","使用宿主机网络","高性能，无隔离"],["overlay","跨主机网络","Swarm 集群"],["macvlan","为容器分配 MAC 地址","需要容器像独立主机"],["none","无网络","完全隔离"]]},{type:"heading",text:"网络操作"},{type:"code",lang:"bash",code:"# 创建网络\ndocker network create my-network\n\n# 创建带驱动的网络\ndocker network create -d overlay my-overlay-network\n\n# 创建带子网的网桥网络\ndocker network create \\\n  --driver bridge \\\n  --subnet 172.28.0.0/16 \\\n  --ip-range 172.28.5.0/24 \\\n  --gateway 172.28.5.254 \\\n  my-br-network\n\n# 查看网络\ndocker network ls\n\n# 查看网络详情\ndocker network inspect my-network\n\n# 连接容器到网络\ndocker network connect my-network mycontainer\n\n# 断开网络连接\ndocker network disconnect my-network mycontainer\n\n# 删除网络\ndocker network rm my-network"}]},{id:"storage",title:"存储管理",content:[{type:"heading",text:"数据卷 (Volume)"},{type:"paragraph",text:"数据卷是由 Docker 管理的存储，独立于容器生命周期，适合持久化数据。"},{type:"code",lang:"bash",code:"# 创建数据卷\ndocker volume create my-volume\n\n# 查看数据卷\ndocker volume ls\n\n# 查看数据卷详情\ndocker volume inspect my-volume\n\n# 使用数据卷启动容器\ndocker run -d -v my-volume:/app/data nginx\n\n# 删除数据卷\ndocker volume rm my-volume\n\n# 清理未使用的数据卷\ndocker volume prune"},{type:"heading",text:"绑定挂载 (Bind Mount)"},{type:"code",lang:"bash",code:"# 挂载宿主机目录\ndocker run -d -v /host/path:/container/path nginx\n\n# 只读挂载\ndocker run -d -v /host/path:/container/path:ro nginx\n\n# 挂载单个文件\ndocker run -d -v /host/config.conf:/etc/config.conf nginx"},{type:"heading",text:"tmpfs 挂载"},{type:"paragraph",text:"tmpfs 挂载存储在内存中，容器删除后数据丢失，适合临时数据。"},{type:"code",lang:"bash",code:"# 创建 tmpfs 挂载\ndocker run -d --tmpfs /tmp:rw,size=100m nginx"}]},{id:"security",title:"安全最佳实践",content:[{type:"heading",text:"镜像安全"},{type:"list",items:["<strong>使用官方镜像</strong>：优先使用 Docker Hub 官方镜像","<strong>定期更新</strong>：及时更新基础镜像和安全补丁","<strong>扫描漏洞</strong>：使用 docker scan 扫描镜像漏洞","<strong>最小化镜像</strong>：只包含必要的组件","<strong>不存储敏感信息</strong>：避免在镜像中存储密码密钥"]},{type:"heading",text:"容器安全"},{type:"code",lang:"bash",code:'# 以非 root 用户运行容器\ndocker run -u 1000:1000 nginx\n\n# 只读文件系统\ndocker run --read-only nginx\n\n# 限制容器资源\ndocker run \\\n  --memory="512m" \\\n  --cpus="1.5" \\\n  --pids-limit 100 \\\n  nginx\n\n# 使用 --security-opt\ndocker run --security-opt=no-new-privileges nginx\n\n# AppArmor 配置\ndocker run --security-opt apparmor=docker-default nginx'},{type:"heading",text:"镜像扫描"},{type:"code",lang:"bash",code:"# 扫描镜像漏洞\ndocker scan my-image:latest\n\n# 使用 Trivy 扫描\ntrivy image my-image:latest"},{type:"heading",text:"使用 Secrets 管理敏感数据"},{type:"code",lang:"yaml",code:"# docker-compose.yml\nversion: '3.8'\n\nservices:\n  app:\n    image: myapp\n    secrets:\n      - db_password\n      - api_key\n\nsecrets:\n  db_password:\n    file: ./secrets/db_password.txt\n  api_key:\n    file: ./secrets/api_key.txt"}]},{id:"production",title:"生产环境部署",content:[{type:"heading",text:"资源限制"},{type:"code",lang:"yaml",code:"# docker-compose.yml\nversion: '3.8'\n\nservices:\n  app:\n    image: myapp:latest\n    deploy:\n      resources:\n        limits:\n          cpus: '1'\n          memory: 512M\n        reservations:\n          cpus: '0.5'\n          memory: 256M\n    restart: always"},{type:"heading",text:"日志管理"},{type:"code",lang:"json",code:'{\n  "log-driver": "json-file",\n  "log-opts": {\n    "max-size": "10m",\n    "max-file": "3",\n    "labels": "production",\n    "compress": "true"\n  }\n}'},{type:"heading",text:"健康检查"},{type:"code",lang:"yaml",code:'# docker-compose.yml\nhealthcheck:\n  test: ["CMD", "curl", "-f", "http://localhost:3000/health"]\n  interval: 30s\n  timeout: 10s\n  retries: 3\n  start_period: 40s'},{type:"heading",text:"CI/CD 集成"},{type:"code",lang:"yaml",code:"# GitHub Actions 示例\nname: Docker Build and Deploy\n\non:\n  push:\n    branches: [ main ]\n\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n\n      - name: Set up Docker Buildx\n        uses: docker/setup-buildx-action@v2\n\n      - name: Login to Docker Hub\n        uses: docker/login-action@v2\n        with:\n          username: ${{ secrets.DOCKER_USERNAME }}\n          password: ${{ secrets.DOCKER_PASSWORD }}\n\n      - name: Build and push\n        uses: docker/build-push-action@v4\n        with:\n          context: .\n          push: true\n          tags: user/app:latest\n          cache-from: type=gha\n          cache-to: type=gha,mode=max"}]}]},go:{name:"Go",icon:"G",color:"from-cyan-500 to-blue-600",chapters:[{id:"intro",title:"Go 语言简介",content:[{type:"heading",text:"什么是 Go"},{type:"paragraph",text:"Go (Golang) 是 Google 开发的一门开源编程语言，专注于简洁、高效和并发。适合构建云原生应用、微服务、DevOps 工具等。"},{type:"heading",text:"核心特性"},{type:"list",items:["<strong>简洁语法</strong>：25个关键字，学习曲线平缓","<strong>原生并发</strong>：Goroutine 和 Channel，轻量级并发模型","<strong>高性能</strong>：接近 C 语言的性能，编译型语言","<strong>垃圾回收</strong>：高效的 GC 实现，低延迟","<strong>静态类型</strong>：类型安全，编译期检查","<strong>标准库丰富</strong>：net/http、database/sql 等开箱即用","<strong>跨平台</strong>：支持交叉编译，一次编译到处运行"]},{type:"heading",text:"应用场景"},{type:"list",items:["微服务架构","云原生应用 (Kubernetes、Docker 都是用 Go 编写)","网络编程和 API 服务","DevOps 工具","区块链开发","分布式系统"]}]},{id:"basic-syntax",title:"基础语法",content:[{type:"heading",text:"变量与常量"},{type:"code",lang:"go",code:'package main\n\nimport "fmt"\n\n// 变量声明\nvar name string = "Alice"\nvar age = 25  // 类型推导\n\n// 短变量声明（函数内使用）\nfunc main() {\n    city := "Beijing"  // 最常用\n\n    // 常量\n    const PI = 3.14\n    const MaxUsers = 1000\n\n    // 多变量声明\n    x, y := 10, 20\n\n    fmt.Printf("%s is %d years old\\n", name, age)\n}'},{type:"heading",text:"数据类型"},{type:"code",lang:"go",code:"// 基本类型\nvar b bool = true           // 布尔\nvar i int = 42              // 整型（int8, int16, int32, int64）\nvar f float64 = 3.14        // 浮点（float32, float64）\nvar s string = \"hello\"      // 字符串\nvar b byte = 'a'            // 字节（uint8 别名）\nvar r rune = '中'           // Unicode 字符（int32 别名）\n\n// 复合类型\nvar arr [3]int = [3]int{1, 2, 3}           // 数组\nvar slice []int = []int{1, 2, 3}            // 切片\nvar m map[string]int = make(map[string]int) // Map\n"},{type:"heading",text:"指针"},{type:"code",lang:"go",code:"func main() {\n    x := 42\n    p := &x  // p 是指向 x 的指针\n\n    fmt.Println(*p) // 输出 42（解引用）\n    fmt.Println(p)  // 输出内存地址\n\n    *p = 100       // 通过指针修改 x\n    fmt.Println(x) // 输出 100\n}"},{type:"heading",text:"控制结构"},{type:"code",lang:"go",code:'// if 语句（无括号）\nif x > 0 {\n    fmt.Println("positive")\n} else if x < 0 {\n    fmt.Println("negative")\n} else {\n    fmt.Println("zero")\n}\n\n// if 带初始化\nif err := doSomething(); err != nil {\n    return err\n}\n\n// for 循环（Go 只有 for）\nfor i := 0; i < 10; i++ {\n    fmt.Println(i)\n}\n\n// while 风格\nfor condition {\n    // 循环体\n}\n\n// 无限循环\nfor {\n    // 永远执行\n}\n\n// 遍历 slice/map\nfor i, v := range slice {\n    fmt.Printf("index: %d, value: %d\\n", i, v)\n}\n\nfor k, v := range myMap {\n    fmt.Printf("key: %s, value: %d\\n", k, v)\n}\n\n// switch\nswitch value {\ncase 1:\n    fmt.Println("one")\ncase 2:\n    fmt.Println("two")\ndefault:\n    fmt.Println("other")\n}'}]},{id:"functions",title:"函数",content:[{type:"heading",text:"函数定义"},{type:"code",lang:"go",code:'// 基本函数\nfunc add(a, b int) int {\n    return a + b\n}\n\n// 多返回值（Go 特色）\nfunc divide(a, b int) (int, error) {\n    if b == 0 {\n        return 0, fmt.Errorf("division by zero")\n    }\n    return a / b, nil\n}\n\n// 命名返回值\nfunc rectangle(width, height int) (area int, perimeter int) {\n    area = width * height\n    perimeter = 2 * (width + height)\n    return  // 自动返回 area 和 perimeter\n}\n\n// 可变参数\nfunc sum(nums ...int) int {\n    total := 0\n    for _, num := range nums {\n        total += num\n    }\n    return total\n}\n\n// 使用\nresult, err := divide(10, 2)\nif err != nil {\n    log.Fatal(err)\n}'},{type:"heading",text:"闭包与函数作为值"},{type:"code",lang:"go",code:"// 函数作为类型\ntype Operation func(int, int) int\n\nfunc apply(op Operation, a, b int) int {\n    return op(a, b)\n}\n\n// 闭包\nfunc makeAdder(x int) func(int) int {\n    return func(y int) int {\n        return x + y\n    }\n}\n\nadder := makeAdder(10)\nfmt.Println(adder(5)) // 输出 15"},{type:"heading",text:"defer 延迟执行"},{type:"code",lang:"go",code:'func processFile(filename string) error {\n    file, err := os.Open(filename)\n    if err != nil {\n        return err\n    }\n    defer file.Close()  // 函数返回前执行\n\n    // 处理文件...\n    return nil\n}\n\n// 多个 defer 按栈顺序执行（LIFO）\nfunc example() {\n    defer fmt.Println("first")\n    defer fmt.Println("second")\n    defer fmt.Println("third")\n}\n// 输出：third, second, first'}]},{id:"struct",title:"结构体与方法",content:[{type:"heading",text:"结构体定义"},{type:"code",lang:"go",code:'// 定义结构体\ntype User struct {\n    ID       int\n    Name     string\n    Email    string\n    CreateAt time.Time\n}\n\n// 创建实例\nu1 := User{ID: 1, Name: "Alice"}   // 指定字段\nu2 := User{1, "Bob", "bob@e.com"}  // 按顺序\nu3 := new(User)                    // 返回指针\nu3.Name = "Charlie"\n\n// 匿名结构体\nperson := struct {\n    Name string\n    Age  int\n}{\n    Name: "David",\n    Age:  30,\n}'},{type:"heading",text:"方法"},{type:"code",lang:"go",code:'// 值接收者\nfunc (u User) GetName() string {\n    return u.Name\n}\n\n// 指针接收者（可修改结构体）\nfunc (u *User) SetName(name string) {\n    u.Name = name\n}\n\n// 接口实现\ntype Stringer interface {\n    String() string\n}\n\nfunc (u User) String() string {\n    return fmt.Sprintf("User(%d, %s)", u.ID, u.Name)\n}'},{type:"heading",text:"接口"},{type:"code",lang:"go",code:'// 定义接口\ntype Writer interface {\n    Write([]byte) (int, error)\n    Close() error\n}\n\n// 实现（隐式，无需显式声明）\ntype FileWriter struct {\n    file *os.File\n}\n\nfunc (fw *FileWriter) Write(data []byte) (int, error) {\n    return fw.file.Write(data)\n}\n\nfunc (fw *FileWriter) Close() error {\n    return fw.file.Close()\n}\n\n// 空接口（interface{}）可接收任何类型\nfunc printAny(v interface{}) {\n    fmt.Println(v)\n}\n\n// 类型断言\nvar i interface{} = "hello"\ns, ok := i.(string)\nif ok {\n    fmt.Println(s)\n}\n\n// 类型 switch\nswitch v := i.(type) {\ncase int:\n    fmt.Println("整数:", v)\ncase string:\n    fmt.Println("字符串:", v)\ndefault:\n    fmt.Println("其他类型")\n}'}]},{id:"concurrency",title:"并发编程",content:[{type:"heading",text:"Goroutine"},{type:"paragraph",text:"Goroutine 是 Go 的轻量级线程，由 Go 运行时管理，只需在函数调用前加 go 关键字。"},{type:"code",lang:"go",code:'func sayHello() {\n    fmt.Println("Hello from goroutine")\n}\n\nfunc main() {\n    // 启动 goroutine\n    go sayHello()\n\n    // 匿名函数 goroutine\n    go func(msg string) {\n        fmt.Println(msg)\n    }!("Hello")\n\n    // 等待 goroutine（通常用 WaitGroup）\n    time.Sleep(time.Second)\n}'},{type:"heading",text:"Channel 通道"},{type:"code",lang:"go",code:'// 创建 channel\nch := make(chan int)\n\n// 发送\ngo func() {\n    ch <- 42  // 发送数据到 channel\n}()\n\n// 接收\nvalue := <-ch  // 从 channel 接收数据\n\n// 缓冲 channel\nbuffered := make(chan int, 10)\n\n// 只读/只写 channel\nfunc producer(ch chan<- int) {\n    ch <- 1\n}\n\nfunc consumer(ch <-chan int) {\n    <-ch\n}\n\n// select 多路复用\nselect {\ncase msg := <-ch1:\n    fmt.Println("from ch1:", msg)\ncase msg := <-ch2:\n    fmt.Println("from ch2:", msg)\ncase <-time.After(time.Second):\n    fmt.Println("timeout")\n}'},{type:"heading",text:"sync 包"},{type:"code",lang:"go",code:'// WaitGroup 等待一组 goroutine\nvar wg sync.WaitGroup\n\nfor i := 0; i < 5; i++ {\n    wg.Add(1)\n    go func(n int) {\n        defer wg.Done()\n        fmt.Println("Worker", n)\n    }(i)\n}\nwg.Wait()\n\n// Mutex 互斥锁\nvar mu sync.Mutex\nvar count int\n\nfunc increment() {\n    mu.Lock()\n    count++\n    mu.Unlock()\n}\n\n// Once 只执行一次\nvar once sync.Once\nfunc init() {\n    once.Do(func() {\n        // 初始化代码只执行一次\n    })\n}\n\n// Context 上下文控制\nfunc worker(ctx context.Context) {\n    for {\n        select {\n        case <-ctx.Done():\n            fmt.Println("cancelled")\n            return\n        default:\n            // 工作...\n        }\n    }\n}\n\nctx, cancel := context.WithCancel(context.Background())\ngo worker(ctx)\ncancel()  // 取消所有监听该 ctx 的 goroutine'}]},{id:"error-handling",title:"错误处理",content:[{type:"heading",text:"错误处理模式"},{type:"paragraph",text:"Go 没有异常机制，使用返回值表示错误。"},{type:"code",lang:"go",code:'// 基本错误处理\nfunc readFile(path string) ([]byte, error) {\n    data, err := os.ReadFile(path)\n    if err != nil {\n        return nil, fmt.Errorf("read file failed: %w", err)\n    }\n    return data, nil\n}\n\n// 使用\ndata, err := readFile("config.json")\nif err != nil {\n    log.Printf("error: %v", err)\n    return\n}\n\n// 自定义错误\ntype ValidationError struct {\n    Field   string\n    Message string\n}\n\nfunc (e *ValidationError) Error() string {\n    return fmt.Sprintf("%s: %s", e.Field, e.Message)\n}\n\n// panic 和 recover（类似异常）\nfunc safeOperation() {\n    defer func() {\n        if r := recover(); r != nil {\n            log.Printf("recovered from panic: %v", r)\n        }\n    }()\n\n    // 可能 panic 的代码\n    panic("something went wrong")\n}'}]},{id:"web",title:"Web 开发",content:[{type:"heading",text:"HTTP Server"},{type:"code",lang:"go",code:'package main\n\nimport (\n    "encoding/json"\n    "net/http"\n)\n\ntype User struct {\n    Name string `json:"name"`\n    Email string `json:"email"`\n}\n\nfunc main() {\n    // 路由\n    http.HandleFunc("/", homeHandler)\n    http.HandleFunc("/api/users", usersHandler)\n\n    // 启动服务器\n    http.ListenAndServe(":8080", nil)\n}\n\nfunc homeHandler(w http.ResponseWriter, r *http.Request) {\n    w.Write([]byte("Welcome!"))\n}\n\nfunc usersHandler(w http.ResponseWriter, r *http.Request) {\n    users := []User{\n        {Name: "Alice", Email: "alice@example.com"},\n        {Name: "Bob", Email: "bob@example.com"},\n    }\n\n    w.Header().Set("Content-Type", "application/json")\n    json.NewEncoder(w).Encode(users)\n}'},{type:"heading",text:"Gin 框架"},{type:"code",lang:"go",code:'package main\n\nimport (\n    "github.com/gin-gonic/gin"\n    "net/http"\n)\n\ntype User struct {\n    Name  string `json:"name" binding:"required"`\n    Email string `json:"email" binding:"required,email"`\n}\n\nfunc main() {\n    r := gin.Default()\n\n    // 中间件\n    r.Use(Logger())\n\n    // 路由组\n    api := r.Group("/api/v1")\n    {\n        api.GET("/users", GetUsers)\n        api.POST("/users", CreateUser)\n        api.GET("/users/:id", GetUser)\n    }\n\n    r.Run(":8080")\n}\n\nfunc GetUsers(c *gin.Context) {\n    users := []User{...}\n    c.JSON(http.StatusOK, gin.H{"data": users})\n}\n\nfunc CreateUser(c *gin.Context) {\n    var user User\n    if err := c.ShouldBindJSON(&user); err != nil {\n        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})\n        return\n    }\n    // 保存用户...\n    c.JSON(http.StatusCreated, gin.H{"data": user})\n}'}]},{id:"testing",title:"测试",content:[{type:"heading",text:"单元测试"},{type:"code",lang:"go",code:'// calculator.go\nfunc Add(a, b int) int {\n    return a + b\n}\n\n// calculator_test.go\npackage calculator\n\nimport "testing"\n\nfunc TestAdd(t *testing.T) {\n    tests := []struct {\n        name string\n        a, b int\n        want int\n    }{\n        {"positive", 2, 3, 5},\n        {"negative", -1, -1, -2},\n        {"zero", 0, 0, 0},\n    }\n\n    for _, tt := range tests {\n        t.Run(tt.name, func(t *testing.T) {\n            if got := Add(tt.a, tt.b); got != tt.want {\n                t.Errorf("Add() = %v, want %v", got, tt.want)\n            }\n        })\n    }\n}'},{type:"heading",text:"基准测试"},{type:"code",lang:"go",code:"func BenchmarkAdd(b *testing.B) {\n    for i := 0; i < b.N; i++ {\n        Add(1, 2)\n    }\n}\n\n// 运行：go test -bench=. -benchmem"},{type:"heading",text:"表驱动测试"},{type:"code",lang:"go",code:'func TestValidateEmail(t *testing.T) {\n    tests := []struct {\n        email string\n        valid bool\n    }{\n        {"test@example.com", true},\n        {"invalid-email", false},\n        {"", false},\n    }\n\n    for _, tt := range tests {\n        got := ValidateEmail(tt.email)\n        if got != tt.valid {\n            t.Errorf("%s: got %v, want %v", tt.email, got, tt.valid)\n        }\n    }\n}'}]},{id:"project-structure",title:"项目结构",content:[{type:"heading",text:"标准项目布局"},{type:"code",lang:"text",code:"myapp/\n├── cmd/                    # 主应用程序\n│   └── myapp/\n│       └── main.go\n├── internal/               # 私有应用和库代码\n│   ├── handler/\n│   ├── model/\n│   ├── repository/\n│   └── service/\n├── pkg/                    # 可被外部使用的库\n├── api/                    # API 定义文件\n│   ├── http/\n│   └── grpc/\n├── configs/                # 配置文件\n├── scripts/                # 构建、安装脚本\n├── test/                   # 额外的测试数据\n├── docs/                   # 文档\n├── go.mod\n└── go.sum"},{type:"heading",text:"依赖管理"},{type:"code",lang:"bash",code:"# 初始化模块\ngo mod init myapp\n\n# 添加依赖\ngo get github.com/gin-gonic/gin\n\n# 添加特定版本\ngo get github.com/gin-gonic/gin@v1.9.0\n\n# 下载依赖到 vendor\ngo mod vendor\n\n# 整理依赖\ngo mod tidy\n\n# 更新依赖\ngo get -u ./...\n\n# 验证依赖\ngo mod verify"}]}]},redis:{name:"Redis",icon:"R",color:"from-red-500 to-red-700",chapters:[{id:"intro",title:"Redis 简介",content:[{type:"heading",text:"什么是 Redis"},{type:"paragraph",text:"Redis (Remote Dictionary Server) 是开源的内存数据结构存储，可用作数据库、缓存、消息代理和流引擎。支持多种数据结构，并提供持久化、主从复制、集群等功能。"},{type:"heading",text:"核心特性"},{type:"list",items:["<strong>内存存储</strong>：所有数据存储在内存中，读写速度极快","<strong>丰富数据结构</strong>：String、Hash、List、Set、ZSet、Stream 等","<strong>持久化</strong>：RDB 快照和 AOF 日志两种方式","<strong>主从复制</strong>：支持数据复制，实现高可用","<strong>集群</strong>：支持水平扩展","<strong>单线程模型</strong>：避免锁竞争，简化实现","<strong>发布订阅</strong>：消息传递机制"]},{type:"heading",text:"应用场景"},{type:"list",items:["<strong>缓存</strong>：热点数据缓存，减轻数据库压力","<strong>会话存储</strong>：分布式 session 存储","<strong>排行榜</strong>：使用 ZSet 实现排行榜","<strong>计数器</strong>：原子性计数","<strong>分布式锁</strong>：SET NX EX 实现","<strong>消息队列</strong>：List 或 Stream 实现队列","<strong>限流</strong>：滑动窗口算法"]}]},{id:"data-types",title:"数据类型",content:[{type:"heading",text:"String 字符串"},{type:"code",lang:"bash",code:"# 设置和获取\nSET key value\nGET key\n\n# 设置过期时间（秒）\nSET key value EX 60\n\n# 不存在时设置\nSETNX key value\n\n# 批量设置\nMSET key1 value1 key2 value2\n\n# 计数\nINCR counter\nINCRBY counter 10\nDECR counter\nDECRBY counter 5"},{type:"heading",text:"Hash 哈希"},{type:"code",lang:"bash",code:'# 设置字段\nHSET user:1 name "Alice" age 25\n\n# 获取字段\nHGET user:1 name\nHGETALL user:1\n\n# 检查字段存在\nHEXISTS user:1 email\n\n# 获取所有字段\nHKEYS user:1\nHVALS user:1\n\n# 增加数值\nHINCRBY user:1 age 1'},{type:"heading",text:"List 列表"},{type:"code",lang:"bash",code:"# 左侧推入（队列）\nLPUSH queue item1 item2\n\n# 右侧弹出\nRPOP queue\n\n# 右侧推入（栈）\nRPUSH stack item\n\n# 范围查询\nLRANGE list 0 -1\n\n# 列表长度\nLLEN list\n\n# 阻塞弹出（消息队列）\nBLPOP queue 0"},{type:"heading",text:"Set 集合"},{type:"code",lang:"bash",code:"# 添加成员\nSADD set1 item1 item2 item3\n\n# 获取所有成员\nSMEMBERS set1\n\n# 检查存在\nSISMEMBER set1 item1\n\n# 集合运算\nSINTER set1 set2      # 交集\nSUNION set1 set2      # 并集\nSDIFF set1 set2       # 差集\n\n# 随机获取\nSRANDMEMBER set1\nSPOP set1"},{type:"heading",text:"ZSet 有序集合"},{type:"code",lang:"bash",code:'# 添加成员（分数）\nZADD leaderboard 100 "player1" 200 "player2" 150 "player3"\n\n# 范围查询（升序）\nZRANGE leaderboard 0 -1\n\n# 范围查询（降序）\nZREVRANGE leaderboard 0 -1\n\n# 带分数查询\nZRANGE leaderboard 0 -1 WITHSCORES\n\n# 分数范围查询\nZRANGEBYSCORE leaderboard 100 200\n\n# 获取排名\nZRANK leaderboard "player1"      # 升序排名\nZREVRANK leaderboard "player1"   # 降序排名\n\n# 增加分数\nZINCRBY leaderboard 10 "player1"'},{type:"heading",text:"Stream 流（Redis 5.0+）"},{type:"code",lang:"bash",code:"# 添加消息\nXADD mystream * sensor temp 25.5\n\n# 读取消息\nXREAD STREAMS mystream 0\n\n# 消费者组\nXGROUP CREATE mystream mygroup 0\n\n# 从组读取\nXREADGROUP GROUP mygroup consumer1 STREAMS mystream >"}]},{id:"persistence",title:"持久化机制",content:[{type:"heading",text:"RDB 快照"},{type:"paragraph",text:"RDB 在指定时间间隔内生成数据集的时间点快照。"},{type:"code",lang:"bash",code:"# 手动触发快照\nSAVE    # 阻塞式\nBGSAVE  # 异步\n\n# 配置\nsave 900 1      # 900秒内至少1个key变化\nsave 300 10     # 300秒内至少10个key变化\nsave 60 10000   # 60秒内至少10000个key变化\n\n# 压缩\nrdbcompression yes\n\n# 快照文件名\ndbfilename dump.rdb"},{type:"heading",text:"AOF 日志"},{type:"paragraph",text:"AOF 记录每个写操作命令，恢复时重新执行。"},{type:"code",lang:"bash",code:'# 启用 AOF\nappendonly yes\n\n# AOF 文件名\nappendfilename "appendonly.aof"\n\n# 同步策略\nappendfsync always    # 每次写入同步（最安全）\nappendfsync everysec  # 每秒同步（推荐）\nappendfsync no        # 由操作系统决定\n\n# AOF 重写配置\nauto-aof-rewrite-percentage 100\nauto-aof-rewrite-min-size 64mb'},{type:"heading",text:"混合持久化（RDB+AOF）"},{type:"paragraph",text:"Redis 4.0+ 支持混合持久化，AOF 重写时将 RDB 内容写入 AOF 文件开头。"},{type:"code",lang:"bash",code:"aof-use-rdb-preamble yes"}]},{id:"replication",title:"主从复制",content:[{type:"heading",text:"复制原理"},{type:"list",items:["<strong>全量同步</strong>：从节点首次连接或无法部分同步时进行","<strong>部分同步</strong>：复制偏移量在复制积压缓冲区内","<strong>异步复制</strong>：主节点处理完命令后异步发送给从节点"]},{type:"heading",text:"配置主从"},{type:"code",lang:"bash",code:"# 从节点配置\nreplicaof <masterip> <masterport>\n\n# 主节点密码（如果有）\nmasterauth <password>\n\n# 只读模式\nreplica-serve-stale-data yes"},{type:"heading",text:"哨兵 Sentinel"},{type:"paragraph",text:"哨兵监控主从节点，自动故障转移。"},{type:"code",lang:"bash",code:"# sentinel.conf\nport 26379\n\n# 监控主节点\nsentinel monitor mymaster 127.0.0.1 6379 2\n\n# 主节点密码\nsentinel auth-pass mymaster <password>\n\n# 故障转移配置\nsentinel down-after-milliseconds mymaster 5000\nsentinel parallel-syncs mymaster 1\nsentinel failover-timeout mymaster 30000"}]},{id:"cluster",title:"集群",content:[{type:"heading",text:"集群架构"},{type:"list",items:["<strong>分片</strong>：16384 个哈希槽，数据分散到多个节点","<strong>高可用</strong>：每个主节点有多个从节点","<strong>自动故障转移</strong>：主节点故障时从节点提升为主节点"]},{type:"heading",text:"集群配置"},{type:"code",lang:"bash",code:"# 启用集群\ncluster-enabled yes\ncluster-config-file nodes.conf\ncluster-node-timeout 5000\n\n# 创建集群（6个节点，3主3从）\nredis-cli --cluster create \\\n  127.0.0.1:7001 127.0.0.1:7002 127.0.0.1:7003 \\\n  127.0.0.1:7004 127.0.0.1:7005 127.0.0.1:7006 \\\n  --cluster-replicas 1"},{type:"heading",text:"集群操作"},{type:"code",lang:"bash",code:"# 连接集群\nredis-cli -c -p 7001\n\n# 查看集群状态\ncluster info\n\n# 查看节点\ncluster nodes\n\n# 添加节点\nredis-cli --cluster add-node new_node:7001 existing_node:7001\n\n# 删除节点\nredis-cli --cluster del-node node_ip:7001 node_id\n\n# 重新分片\nredis-cli --cluster reshard existing_node:7001"}]},{id:"performance",title:"性能优化",content:[{type:"heading",text:"内存优化"},{type:"list",items:["<strong>设置过期时间</strong>：及时清理无效数据","<strong>选择合适的数据结构</strong>：如用 Hash 代替多个 String","<strong>使用压缩列表</strong>：小数据量自动使用压缩","<strong>禁用 THP</strong>：Transparent Huge Pages 影响性能"]},{type:"heading",text:"命令优化"},{type:"list",items:["<strong>避免 KEYS</strong>：使用 SCAN 代替 KEYS","<strong>批量操作</strong>：使用 MGET、MSET 等批量命令","<strong>使用 Pipeline</strong>：减少网络往返","<strong>使用 Lua 脚本</strong>：复杂原子操作"]},{type:"heading",text:"Pipeline 示例"},{type:"code",lang:"bash",code:"# 使用 Pipeline 批量执行\necho -e '\nSET key1 value1\nSET key2 value2\nGET key1\n' | redis-cli --pipe"},{type:"heading",text:"Lua 脚本"},{type:"code",lang:"bash",code:"# 限流脚本\nlocal key = KEYS[1]\nlocal limit = tonumber(ARGV[1])\nlocal expire = tonumber(ARGV[2])\n\nlocal current = redis.call('GET', key) or 0\nif current + 1 > limit then\n  return 0\nelse\n  redis.call('INCR', key)\n  redis.call('EXPIRE', key, expire)\n  return 1\nend\n\n# 执行脚本\nredis-cli --eval limit.lua key1 , 100 60"}]},{id:"patterns",title:"常见应用模式",content:[{type:"heading",text:"分布式锁"},{type:"code",lang:"bash",code:'# 加锁（SET NX EX）\nSET lock:resource1 unique_value NX EX 10\n\n# 解锁（Lua 保证原子性）\nif redis.call("GET", KEYS[1]) == ARGV[1] then\n    return redis.call("DEL", KEYS[1])\nelse\n    return 0\nend'},{type:"heading",text:"限流"},{type:"code",lang:"bash",code:"# 滑动窗口限流\nZADD rate_limit:user1 timestamp now\nZREMRANGEBYSCORE rate_limit:user1 0 (now-60s\nZCARD rate_limit:user1\n\n# 如果 count > limit 则拒绝"},{type:"heading",text:"排行榜"},{type:"code",lang:"bash",code:"# 添加分数\nZADD leaderboard 100 player1\n\n# 获取 Top 10\nZREVRANGE leaderboard 0 9 WITHSCORES\n\n# 获取用户排名\nZREVRANK leaderboard player1"},{type:"heading",text:"消息队列"},{type:"code",lang:"bash",code:"# 生产者\nLPUSH queue task1\n\n# 消费者\nRPOP queue\n\n# 阻塞式消费\nBRPOP queue 0"}]}]},nginx:{name:"Nginx",icon:"N",color:"from-green-500 to-green-700",chapters:[{id:"intro",title:"Nginx 简介",content:[{type:"heading",text:"什么是 Nginx"},{type:"paragraph",text:"Nginx 是高性能的 HTTP 服务器和反向代理服务器，也可以作为 IMAP/POP3/SMTP 代理服务器。以高并发、低内存占用著称，适合处理静态资源、负载均衡、反向代理等场景。"},{type:"heading",text:"核心特性"},{type:"list",items:["<strong>高性能</strong>：基于事件驱动模型，可处理数万并发连接","<strong>低内存</strong>：10,000 个非活跃连接约 2.5MB 内存","<strong>热部署</strong>：配置变更无需中断服务","<strong>反向代理</strong>：支持多种协议的代理","<strong>负载均衡</strong>：内置多种负载均衡算法","<strong>静态文件服务</strong>：高效的静态资源处理","<strong>SSL/TLS</strong>：支持 HTTPS 和 SNI"]},{type:"heading",text:"应用场景"},{type:"list",items:["Web 服务器","反向代理","负载均衡器","API 网关","静态资源服务","WebSocket 代理","SSL 卸载"]}]},{id:"basic-config",title:"基础配置",content:[{type:"heading",text:"配置文件结构"},{type:"code",lang:"nginx",code:"# 全局配置\nworker_processes auto;          # 工作进程数\nworker_cpu_affinity auto;        # CPU 亲和性\nworker_rlimit_nofile 65535;      # 文件描述符限制\n\nevents {\n    use epoll;                    # 事件驱动模型\n    worker_connections 10240;     # 每个工作进程最大连接数\n    multi_accept on;              # 同时接受多个连接\n}\n\nhttp {\n    # 基础配置\n    include /etc/nginx/mime.types;\n    default_type application/octet-stream;\n\n    # 日志格式\n    log_format main '$remote_addr - $remote_user [$time_local] \"$request\" '\n                    '$status $body_bytes_sent \"$http_referer\" '\n                    '\"$http_user_agent\" \"$http_x_forwarded_for\" '\n                    '$request_time $upstream_response_time';\n\n    # 性能优化\n    sendfile on;\n    tcp_nopush on;\n    tcp_nodelay on;\n    keepalive_timeout 65;\n    keepalive_requests 100;\n\n    # Gzip 压缩\n    gzip on;\n    gzip_vary on;\n    gzip_min_length 1024;\n    gzip_types text/plain text/css application/json application/javascript;\n\n    # 虚拟主机\n    include /etc/nginx/conf.d/*.conf;\n}"},{type:"heading",text:"虚拟主机配置"},{type:"code",lang:"nginx",code:'server {\n    listen 80;\n    listen [::]:80;\n    server_name example.com www.example.com;\n\n    # 字符集\n    charset utf-8;\n\n    # 访问日志\n    access_log /var/log/nginx/example.access.log main;\n    error_log /var/log/nginx/example.error.log warn;\n\n    # 根目录\n    root /var/www/example;\n    index index.html index.htm;\n\n    # 静态文件缓存\n    location ~* \\.(jpg|jpeg|png|gif|ico|css|js|svg|woff|woff2)$ {\n        expires 30d;\n        add_header Cache-Control "public, immutable";\n    }\n\n    # 反向代理\n    location /api/ {\n        proxy_pass http://backend;\n        proxy_http_version 1.1;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n        proxy_set_header X-Forwarded-Proto $scheme;\n    }\n\n    # 错误页面\n    error_page 404 /404.html;\n    error_page 500 502 503 504 /50x.html;\n}'}]},{id:"reverse-proxy",title:"反向代理",content:[{type:"heading",text:"基本代理配置"},{type:"code",lang:"nginx",code:"location / {\n    proxy_pass http://127.0.0.1:3000;\n\n    # 传递原始请求头\n    proxy_set_header Host $host;\n    proxy_set_header X-Real-IP $remote_addr;\n    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n    proxy_set_header X-Forwarded-Proto $scheme;\n\n    # 超时配置\n    proxy_connect_timeout 60s;\n    proxy_send_timeout 60s;\n    proxy_read_timeout 60s;\n\n    # 缓冲配置\n    proxy_buffering on;\n    proxy_buffer_size 4k;\n    proxy_buffers 8 4k;\n}"},{type:"heading",text:"WebSocket 代理"},{type:"code",lang:"nginx",code:'location /ws/ {\n    proxy_pass http://backend;\n    proxy_http_version 1.1;\n\n    # WebSocket 需要的请求头\n    proxy_set_header Upgrade $http_upgrade;\n    proxy_set_header Connection "upgrade";\n\n    # 超时配置（WebSocket 需要长连接）\n    proxy_connect_timeout 7d;\n    proxy_send_timeout 7d;\n    proxy_read_timeout 7d;\n}'},{type:"heading",text:"条件代理"},{type:"code",lang:"nginx",code:'# 根据请求头代理不同后端\nmap $http_user_agent $backend_pool {\n    default "backend_default";\n    ~*mobile "backend_mobile";\n}\n\nserver {\n    location / {\n        proxy_pass http://$backend_pool;\n    }\n}\n\n# 根据参数代理\nif ($query_string ~* "version=v2") {\n    proxy_pass http://backend_v2;\n}'}]},{id:"load-balancing",title:"负载均衡",content:[{type:"heading",text:"负载均衡算法"},{type:"table",headers:["算法","说明"],rows:[["轮询 (round_robin)","默认，按顺序分配"],["least_conn","最少连接，分配给活动连接最少的服务器"],["ip_hash","根据客户端 IP 哈希，同一 IP 访问同一服务器"],["hash","自定义 key 哈希"],["random","随机选择（需要 two 参数）"]]},{type:"heading",text:"Upstream 配置"},{type:"code",lang:"nginx",code:"# 基本轮询\nupstream backend {\n    server 192.168.1.10:8080;\n    server 192.168.1.11:8080;\n    server 192.168.1.12:8080;\n}\n\n# 最少连接\nupstream backend {\n    least_conn;\n    server 192.168.1.10:8080;\n    server 192.168.1.11:8080;\n}\n\n# IP 哈希（会话保持）\nupstream backend {\n    ip_hash;\n    server 192.168.1.10:8080;\n    server 192.168.1.11:8080;\n}\n\n# 权重配置\nupstream backend {\n    server 192.168.1.10:8080 weight=3;\n    server 192.168.1.11:8080 weight=2;\n    server 192.168.1.12:8080 weight=1;\n}\n\n# 备用服务器\nupstream backend {\n    server 192.168.1.10:8080;\n    server 192.168.1.11:8080 backup;\n}\n\n# 健康检查\nupstream backend {\n    server 192.168.1.10:8080 max_fails=3 fail_timeout=30s;\n    server 192.168.1.11:8080 max_fails=3 fail_timeout=30s;\n}"}]},{id:"https",title:"HTTPS 配置",content:[{type:"heading",text:"SSL 基础配置"},{type:"code",lang:"nginx",code:'server {\n    listen 443 ssl http2;\n    listen [::]:443 ssl http2;\n    server_name example.com;\n\n    # 证书配置\n    ssl_certificate /etc/nginx/ssl/example.com.crt;\n    ssl_certificate_key /etc/nginx/ssl/example.com.key;\n\n    # SSL 协议和密码套件\n    ssl_protocols TLSv1.2 TLSv1.3;\n    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256;\n    ssl_prefer_server_ciphers off;\n\n    # SSL 会话缓存\n    ssl_session_cache shared:SSL:10m;\n    ssl_session_timeout 10m;\n\n    # OCSP Stapling\n    ssl_stapling on;\n    ssl_stapling_verify on;\n    ssl_trusted_certificate /etc/nginx/ssl/ca-bundle.crt;\n\n    # HSTS\n    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;\n}'},{type:"heading",text:"HTTP 重定向到 HTTPS"},{type:"code",lang:"nginx",code:"server {\n    listen 80;\n    listen [::]:80;\n    server_name example.com;\n\n    # Let's Encrypt 验证\n    location /.well-known/acme-challenge/ {\n        root /var/www/certbot;\n    }\n\n    # 重定向到 HTTPS\n    location / {\n        return 301 https://$server_name$request_uri;\n    }\n}\n\nserver {\n    listen 443 ssl http2;\n    server_name example.com;\n    # ...\n}"}]},{id:"security",title:"安全配置",content:[{type:"heading",text:"请求限制"},{type:"code",lang:"nginx",code:"# 限制请求速率\nlimit_req_zone $binary_remote_addr zone=api_limit:10m rate=10r/s;\n\nlocation /api/ {\n    limit_req zone=api_limit burst=20 nodelay;\n    proxy_pass http://backend;\n}\n\n# 限制连接数\nlimit_conn_zone $binary_remote_addr zone=conn_limit:10m;\n\nserver {\n    limit_conn conn_limit 10;\n}\n\n# 限制带宽\nlocation /download/ {\n    limit_rate 1m;\n}"},{type:"heading",text:"访问控制"},{type:"code",lang:"nginx",code:'# IP 白名单\nlocation /admin/ {\n    allow 192.168.1.0/24;\n    deny all;\n}\n\n# 基本认证\nlocation /admin/ {\n    auth_basic "Restricted Access";\n    auth_basic_user_file /etc/nginx/.htpasswd;\n    # 生成密码: htpasswd -c /etc/nginx/.htpasswd user\n}'},{type:"heading",text:"安全头"},{type:"code",lang:"nginx",code:'# 添加安全响应头\nadd_header X-Frame-Options "SAMEORIGIN" always;\nadd_header X-Content-Type-Options "nosniff" always;\nadd_header X-XSS-Protection "1; mode=block" always;\nadd_header Referrer-Policy "no-referrer-when-downgrade" always;\nadd_header Content-Security-Policy "default-src \'self\' http: https: data: blob: \'unsafe-inline\'" always;\n\n# 隐藏版本号\nserver_tokens off;'}]},{id:"cache",title:"缓存配置",content:[{type:"heading",text:"代理缓存"},{type:"code",lang:"nginx",code:'# 定义缓存路径\nproxy_cache_path /var/cache/nginx levels=1:2 keys_zone=my_cache:10m max_size=1g inactive=60m;\n\nserver {\n    location / {\n        proxy_cache my_cache;\n        proxy_cache_key "$scheme$request_method$host$request_uri";\n        proxy_cache_valid 200 304 10m;\n        proxy_cache_valid 301 302 1h;\n        proxy_cache_valid any 1m;\n\n        # 缓存绕过\n        proxy_cache_bypass $http_cache_control;\n        add_header X-Cache-Status $upstream_cache_status;\n\n        proxy_pass http://backend;\n    }\n}'},{type:"heading",text:"FastCGI 缓存"},{type:"code",lang:"nginx",code:'fastcgi_cache_path /var/cache/nginx/fastcgi levels=1:2 keys_zone=phpcache:100m inactive=60m;\n\nserver {\n    location ~ \\.php$ {\n        fastcgi_cache phpcache;\n        fastcgi_cache_key "$scheme$request_method$host$request_uri";\n        fastcgi_cache_valid 200 60m;\n        fastcgi_cache_bypass $skip_cache;\n        fastcgi_no_cache $skip_cache;\n\n        set $skip_cache 0;\n        if ($query_string ~* "nocache") {\n            set $skip_cache 1;\n        }\n\n        fastcgi_pass unix:/var/run/php-fpm.sock;\n    }\n}'}]},{id:"logging",title:"日志管理",content:[{type:"heading",text:"访问日志配置"},{type:"code",lang:"nginx",code:'# 自定义日志格式\nhttp {\n    log_format main \'$remote_addr - $remote_user [$time_local] \'\n                    \'"$request" $status $body_bytes_sent \'\n                    \'"$http_referer" "$http_user_agent" \'\n                    \'$request_time $upstream_response_time\';\n\n    log_format json \'{\'\n        \'"time": "$time_iso8601",\'\n        \'"remote_addr": "$remote_addr",\'\n        \'"request": "$request",\'\n        \'"status": $status,\'\n        \'"bytes": $body_bytes_sent,\'\n        \'"request_time": $request_time,\'\n        \'"upstream_response_time": "$upstream_response_time"\'\n    \'}\';\n\n    access_log /var/log/nginx/access.log json;\n}'},{type:"heading",text:"日志切割"},{type:"code",lang:"bash",code:"# logrotate 配置\n/var/log/nginx/*.log {\n    daily\n    missingok\n    rotate 14\n    compress\n    delaycompress\n    notifempty\n    create 0640 www-data adm\n    sharedscripts\n    postrotate\n        [ -f /var/run/nginx.pid ] && kill -USR1 `cat /var/run/nginx.pid`\n    endscript\n}"}]}]},postgresql:{name:"PostgreSQL",icon:"P",color:"from-indigo-500 to-blue-700",chapters:[{id:"intro",title:"PostgreSQL 简介",content:[{type:"heading",text:"什么是 PostgreSQL"},{type:"paragraph",text:"PostgreSQL 是功能最强大的开源对象关系数据库系统 (ORDBMS)，拥有超过 35 年的开发历史。以可靠性、数据完整性、正确性著称，支持 SQL 标准并提供丰富的高级特性。"},{type:"heading",text:"核心特性"},{type:"list",items:["<strong>ACID 事务</strong>：完整的事务支持，保证数据一致性","<strong>丰富的数据类型</strong>：JSON/JSONB、数组、XML、几何类型等","<strong>高级索引</strong>：B-tree、Hash、GiST、SP-GiST、GIN、BRIN","<strong>全文搜索</strong>：内置全文检索功能","<strong>扩展性</strong>：支持自定义函数、类型、操作符","<strong>分区表</strong>：原生支持表分区","<strong>逻辑复制</strong>：支持流复制和逻辑复制","<strong>MVCC</strong>：多版本并发控制，无锁读取"]},{type:"heading",text:"应用场景"},{type:"list",items:["企业级应用","地理信息系统 (PostGIS)","金融系统","数据仓库","科学计算","Web 应用后端"]}]},{id:"data-types",title:"数据类型",content:[{type:"heading",text:"基本数据类型"},{type:"code",lang:"sql",code:"-- 数值类型\nsmallint          -- 2字节\ninteger / int     -- 4字节\nbigint            -- 8字节\ndecimal / numeric -- 精确数值\nreal / double     -- 浮点数\n\n-- 字符类型\nvarchar(n)        -- 变长字符串\ntext              -- 无限制变长字符串\nchar(n)           -- 定长字符串\n\n-- 日期时间\ntimestamp         -- 日期和时间（带时区）\ndate              -- 日期\ntime              -- 时间\ninterval          -- 时间间隔\n\n-- 布尔类型\nboolean / bool    -- true/false"},{type:"heading",text:"高级数据类型"},{type:"code",lang:"sql",code:"-- JSON/JSONB\njson              -- 文本存储，保留格式和空格\njsonb             -- 二进制存储，支持索引，查询更快\n\n-- 数组\ninteger[]         -- 整数数组\ntext[][]          -- 二维文本数组\n\n-- 货币类型\nmoney             -- 货币金额\n\n-- UUID\nuuid              -- 通用唯一标识符\n\n-- 网络地址\ninet              -- IPv4/IPv6 地址\ncidr              -- 网络段\nmacaddr           -- MAC 地址\n\n-- 位串\nbit(n)            -- 定长位串\nvarbit(n)         -- 变长位串"},{type:"heading",text:"JSONB 操作"},{type:"code",lang:"sql",code:"-- 创建表\nCREATE TABLE products (\n    id SERIAL PRIMARY KEY,\n    name TEXT,\n    metadata JSONB\n);\n\n-- 插入数据\nINSERT INTO products (name, metadata) VALUES\n('iPhone', '{\"price\": 999, \"storage\": [\"64GB\", \"128GB\"], \"color\": \"black\"}');\n\n-- 查询 JSON 字段\nSELECT metadata->>'price' AS price FROM products;\n\n-- 条件查询\nSELECT * FROM products WHERE metadata->>'price' > '500';\n\n-- 更新 JSON 字段\nUPDATE products\nSET metadata = jsonb_set(metadata, '{price}', '\"899\"')\nWHERE id = 1;\n\n-- JSONB 索引\nCREATE INDEX idx_metadata ON products USING gin(metadata);"}]},{id:"advanced-queries",title:"高级查询",content:[{type:"heading",text:"窗口函数"},{type:"code",lang:"sql",code:"-- ROW_NUMBER 行号\nSELECT id, name, salary,\n    ROW_NUMBER() OVER (ORDER BY salary DESC) AS rank\nFROM employees;\n\n-- RANK 排名（相同值相同排名，跳过）\nSELECT id, name, score,\n    RANK() OVER (ORDER BY score DESC) AS rank\nFROM students;\n\n-- DENSE_RANK 排名（相同值相同排名，不跳过）\nSELECT id, name, score,\n    DENSE_RANK() OVER (ORDER BY score DESC) AS rank\nFROM students;\n\n-- LAG/LEAD 访问前后行\nSELECT id, date, amount,\n    LAG(amount) OVER (ORDER BY date) AS prev_amount\nFROM transactions;\n\n-- 分组聚合\nSELECT department, employee, salary,\n    SUM(salary) OVER (PARTITION BY department) AS dept_total\nFROM employees;"},{type:"heading",text:"CTE (公用表表达式)"},{type:"code",lang:"sql",code:"-- 基本 CTE\nWITH department_avg AS (\n    SELECT department, AVG(salary) AS avg_salary\n    FROM employees\n    GROUP BY department\n)\nSELECT e.name, e.salary, d.avg_salary\nFROM employees e\nJOIN department_avg d ON e.department = d.department;\n\n-- 递归 CTE\nWITH RECURSIVE subordinates AS (\n    -- 初始查询\n    SELECT id, name, manager_id\n    FROM employees\n    WHERE id = 1\n\n    UNION ALL\n\n    -- 递归查询\n    SELECT e.id, e.name, e.manager_id\n    FROM employees e\n    INNER JOIN subordinates s ON e.manager_id = s.id\n)\nSELECT * FROM subordinates;"},{type:"heading",text:"LATERAL JOIN"},{type:"code",lang:"sql",code:"-- LATERAL 允许子查询引用前面表的列\nSELECT *\nFROM departments d\nCROSS JOIN LATERAL (\n    SELECT *\n    FROM employees e\n    WHERE e.department_id = d.id\n    ORDER BY salary DESC\n    LIMIT 3\n) AS top_employees;"}]},{id:"index",title:"索引",content:[{type:"heading",text:"索引类型"},{type:"list",items:["<strong>B-tree</strong>：默认索引，支持范围查询和排序","<strong>Hash</strong>：等值查询优化","<strong>GiST</strong>：几何、全文搜索","<strong>SP-GiST</strong>：空间分区数据","<strong>GIN</strong>：数组、JSONB、全文搜索","<strong>BRIN</strong>：大表块级索引"]},{type:"heading",text:"创建索引"},{type:"code",lang:"sql",code:"-- 普通索引\nCREATE INDEX idx_user_email ON users(email);\n\n-- 唯一索引\nCREATE UNIQUE INDEX idx_user_username ON users(username);\n\n-- 复合索引\nCREATE INDEX idx_order_user_date ON orders(user_id, created_at);\n\n-- 部分索引（带条件）\nCREATE INDEX idx_active_users ON users(email) WHERE is_active = true;\n\n-- 表达式索引\nCREATE INDEX idx_user_lower_email ON users(LOWER(email));\n\n-- JSONB GIN 索引\nCREATE INDEX idx_product_metadata ON products USING gin(metadata);\n\n-- 并发创建索引（不锁表）\nCREATE INDEX CONCURRENTLY idx_user_email ON users(email);"},{type:"heading",text:"索引优化"},{type:"list",items:["<strong>EXPLAIN ANALYZE</strong>：分析查询执行计划","<strong>部分索引</strong>：只索引常用数据","<strong>覆盖索引</strong>：索引包含查询所需字段","<strong>定期重建</strong>：REINDEX TABLE 或 CONCURRENTLY"]},{type:"code",lang:"sql",code:"-- 查看查询计划\nEXPLAIN ANALYZE SELECT * FROM users WHERE email = 'test@example.com';\n\n-- 查看索引使用情况\nSELECT schemaname, tablename, indexname, idx_scan\nFROM pg_stat_user_indexes\nORDER BY idx_scan;"}]},{id:"performance",title:"性能优化",content:[{type:"heading",text:"配置优化"},{type:"code",lang:"bash",code:"# postgresql.conf\n\n# 内存配置\nshared_buffers = 256MB              # 约 25% 内存\neffective_cache_size = 1GB          # 约 50-75% 内存\nwork_mem = 4MB                      # 每个操作内存\nmaintenance_work_mem = 64MB\n\n# WAL 配置\nwal_buffers = 16MB\nmin_wal_size = 1GB\nmax_wal_size = 4GB\nwal_level = replica\n\n# 检查点\ncheckpoint_completion_target = 0.9\ncheckpoint_timeout = 15min\n\n# 并发\nmax_connections = 100\nmax_worker_processes = 8\nmax_parallel_workers_per_gather = 4\nmax_parallel_workers = 8\n\n# 查询优化\nrandom_page_cost = 1.1              # SSD 可设为 1.1\neffective_io_concurrency = 200      # SSD"},{type:"heading",text:"VACUUM 与维护"},{type:"code",lang:"sql",code:"-- 自动清理\nALTER TABLE users SET (autovacuum_vacuum_scale_factor = 0.1);\nALTER TABLE users SET (autovacuum_analyze_scale_factor = 0.05);\n\n-- 手动清理\nVACUUM ANALYZE users;\n\n-- 完全清理（回收空间给系统）\nVACUUM FULL users;\n\n-- 只分析不清理\nANALYZE users;\n\n-- 查看表膨胀情况\nSELECT\n    schemaname,\n    tablename,\n    pg_size_pretty(pg_total_relation_size(schemaname||'.'||tablename)) AS size\nFROM pg_tables\nORDER BY pg_total_relation_size(schemaname||'.'||tablename) DESC;"}]},{id:"replication",title:"主从复制",content:[{type:"heading",text:"流复制配置"},{type:"code",lang:"bash",code:"# 主库配置 (postgresql.conf)\nlisten_addresses = '*'\nwal_level = replica\nmax_wal_senders = 5\nwal_keep_size = 1GB\nsynchronous_commit = on\n\n# pg_hba.conf 添加复制用户\nhost    replication     replicator      192.168.1.0/24      scram-sha-256\n\n# 创建复制用户\nCREATE USER replicator REPLICATION LOGIN PASSWORD 'password';"},{type:"code",lang:"bash",code:"# 从库配置\n# recovery.conf (PostgreSQL 12+ 在 postgresql.conf 或 standby.signal)\nstandby_mode = on\nprimary_conninfo = 'host=192.168.1.10 port=5432 user=replicator password=password'\n\n# 或使用 pg_basebackup 初始化\npg_basebackup -h 192.168.1.10 -D /var/lib/postgresql/data -U replicator -P -v -R"},{type:"heading",text:"复制模式"},{type:"table",headers:["模式","说明"],rows:[["异步复制","主库提交后不等从库确认，性能好"],["同步复制","主库等待至少一个从库确认，数据最安全"],["半同步复制","介于两者之间"]]},{type:"code",lang:"sql",code:"-- 设置同步复制\nALTER SYSTEM SET synchronous_standby_names = 'standby1';\n\n-- 查看复制状态\nSELECT * FROM pg_stat_replication;"}]},{id:"backup",title:"备份与恢复",content:[{type:"heading",text:"逻辑备份 (pg_dump)"},{type:"code",lang:"bash",code:"# 备份整个数据库\npg_dump -U postgres mydb > mydb_backup.sql\n\n# 压缩备份\npg_dump -U postgres mydb | gzip > mydb_backup.sql.gz\n\n# 自定义格式备份（支持并行恢复）\npg_dump -U postgres -F d -j 4 -f mydb_backup mydb\n\n# 只备份表结构\npg_dump -U postgres -s mydb > schema.sql\n\n# 只备份数据\npg_dump -U postgres -a mydb > data.sql\n\n# 恢复\npsql -U postgres mydb < mydb_backup.sql\n\n# 恢复自定义格式备份\npg_restore -U postgres -d mydb -j 4 mydb_backup/"},{type:"heading",text:"物理备份 (pg_basebackup)"},{type:"code",lang:"bash",code:"# 全量备份\npg_basebackup -D /backup/pg_backup -Ft -z -P -U postgres\n\n# 增量备份（需要先有全量备份）\npg_basebackup -D /backup/pg_inc -Ft -z -P -U postgres -X stream"},{type:"heading",text:"PITR (时间点恢复)"},{type:"paragraph",text:"使用 WAL 日志恢复到任意时间点。"},{type:"code",lang:"bash",code:"# 配置归档\narchive_mode = on\narchive_command = 'cp %p /archive/%f'\n\n# 恢复到指定时间\n# recovery.conf\nrestore_command = 'cp /archive/%f %p'\nrecovery_target_time = '2024-01-01 12:00:00'"}]},{id:"security",title:"安全配置",content:[{type:"heading",text:"访问控制"},{type:"code",lang:"bash",code:"# pg_hba.conf 配置\n# TYPE  DATABASE        USER            ADDRESS                 METHOD\n\n# 本地连接\nlocal   all             postgres                                peer\n\n# 本地网络\nhost    all             all             127.0.0.1/32            scram-sha-256\nhost    all             all             ::1/128                 scram-sha-256\n\n# 内网\nhost    all             all             192.168.1.0/24          scram-sha-256\n\n# 复制连接\nhost    replication     replicator      192.168.1.0/24          scram-sha-256"},{type:"heading",text:"权限管理"},{type:"code",lang:"sql",code:"-- 创建角色\nCREATE USER app_user WITH PASSWORD 'secure_password';\n\n-- 授予数据库权限\nGRANT CONNECT ON DATABASE mydb TO app_user;\nGRANT USAGE ON SCHEMA public TO app_user;\nGRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO app_user;\nGRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO app_user;\n\n-- 设置默认权限\nALTER DEFAULT PRIVILEGES IN SCHEMA public\n    GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO app_user;\n\n-- 行级安全 (RLS)\nALTER TABLE users ENABLE ROW LEVEL SECURITY;\n\nCREATE POLICY user_isolation ON users\n    FOR ALL\n    USING (user_id = current_user_id());"}]},{id:"extensions",title:"常用扩展",content:[{type:"heading",text:"PostGIS (地理信息)"},{type:"code",lang:"sql",code:"-- 安装扩展\nCREATE EXTENSION postgis;\n\n-- 创建几何表\nCREATE TABLE locations (\n    id SERIAL PRIMARY KEY,\n    name TEXT,\n    geom GEOMETRY(Point, 4326)\n);\n\n-- 插入位置\nINSERT INTO locations (name, geom) VALUES\n('北京', ST_SetSRID(ST_MakePoint(116.4074, 39.9042), 4326));\n\n-- 距离查询\nSELECT name, ST_Distance(geom, ST_SetSRID(ST_MakePoint(116.4, 39.9), 4326)) AS distance\nFROM locations;"},{type:"heading",text:"pg_trgm (模糊搜索)"},{type:"code",lang:"sql",code:"-- 安装扩展\nCREATE EXTENSION pg_trgm;\n\n-- 创建 GIN 索引\nCREATE INDEX idx_name_trgm ON users USING gin(name gin_trgm_ops);\n\n-- 模糊搜索\nSELECT * FROM users WHERE name LIKE '%john%';\n\n-- 相似度搜索\nSELECT * FROM users WHERE similarity(name, 'john') > 0.3;"},{type:"heading",text:"uuid-ossp"},{type:"code",lang:"sql",code:'-- 安装扩展\nCREATE EXTENSION "uuid-ossp";\n\n-- 生成 UUID\nSELECT uuid_generate_v4();\n\n-- 表中使用\nCREATE TABLE users (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    name TEXT\n);'}]}]}};function e(e){return n[e]||null}function t(){return Object.keys(n)}export{e as a,t as g};
